#!/usr/bin/env python3
"""
Pipeline Executor CLI
Executes pipelines from .pipe files with expression support.
"""

import json
import os
import re
import subprocess
import sys
import time
from abc import ABC, abstractmethod
from dataclasses import dataclass, field
from enum import Enum
from typing import Any, Dict, List, Optional, Tuple, Union

try:
    import toml
except ImportError:
    toml = None


# ============================================================================
# Exceptions
# ============================================================================

class ParseError(Exception):
    """Syntax error in pipeline file."""
    def __init__(self, msg: str):
        self.msg = msg
        super().__init__(msg)


class ValidationError(Exception):
    """Invalid pipeline (circular deps, undefined tasks, etc)."""
    def __init__(self, msg: str):
        self.msg = msg
        super().__init__(msg)


# ============================================================================
# Lexer
# ============================================================================

TokenType = Enum('TokenType', [
    'TASK', 'PARAMS', 'RUN', 'SUCCESS', 'REQUIRES', 'OUTPUT', 'TIMEOUT',
    'FOR', 'WHILE', 'IF', 'ELIF', 'ELSE', 'RETURN', 'BREAK', 'CONTINUE',
    'IDENTIFIER', 'STRING', 'INT', 'FLOAT', 'BOOL',
    'EQ', 'NEQ', 'LT', 'GT', 'LTE', 'GTE', 'AND', 'OR', 'NOT',
    'ASSIGN', 'PLUS', 'MINUS', 'MULT', 'DIV', 'MOD', 'CONCAT',
    'LPAREN', 'RPAREN', 'LBRACE', 'RBRACE', 'LBRACK', 'RBRACK',
    'COLON', 'SEMI', 'COMMA', 'DOT', 'ARROW',
    'EOF', 'NEWLINE', 'WHITESPACE'
])

KEYWORDS = {
    'task': TokenType.TASK,
    'params': TokenType.PARAMS,
    'run': TokenType.RUN,
    'success': TokenType.SUCCESS,
    'requires': TokenType.REQUIRES,
    'output': TokenType.OUTPUT,
    'timeout': TokenType.TIMEOUT,
    'for': TokenType.FOR,
    'while': TokenType.WHILE,
    'if': TokenType.IF,
    'elif': TokenType.ELIF,
    'else': TokenType.ELSE,
    'return': TokenType.RETURN,
    'break': TokenType.BREAK,
    'continue': TokenType.CONTINUE,
}

OP_SYMS = {
    '==': TokenType.EQ, '!=': TokenType.NEQ,
    '<': TokenType.LT, '>': TokenType.GT,
    '<=': TokenType.LTE, '>=': TokenType.GTE,
    '&&': TokenType.AND, '||': TokenType.OR, '!': TokenType.NOT,
    '=': TokenType.ASSIGN, '+': TokenType.PLUS, '-': TokenType.MINUS,
    '*': TokenType.MULT, '/': TokenType.DIV, '%': TokenType.MOD,
    '%': TokenType.CONCAT,
    '(': TokenType.LPAREN, ')': TokenType.RPAREN,
    '{': TokenType.LBRACE, '}': TokenType.RBRACE,
    '[': TokenType.LBRACK, ']': TokenType.RBRACK,
    ':': TokenType.COLON, ';': TokenType.SEMI,
    ',': TokenType.COMMA, '.': TokenType.DOT,
}


@dataclass
class Token:
    type: TokenType
    value: str
    line: int
    col: int

    def __repr__(self):
        return f"{self.type.name}({repr(self.value)})"


class Lexer:
    def __init__(self, source: str):
        self.source = source
        self.pos = 0
        self.line = 1
        self.col = 1

    def peek(self, offset=0) -> str:
        p = self.pos + offset
        return self.source[p] if p < len(self.source) else '\0'

    def advance(self) -> str:
        ch = self.peek()
        if ch == '\n':
            self.line += 1
            self.col = 1
        else:
            self.col += 1
        self.pos += 1
        return ch

    def skip_whitespace(self):
        while self.peek() in ' \t\r':
            self.advance()
        if self.peek() == '\n':
            self.advance()

    def read_identifier(self) -> str:
        start = self.pos
        while self.peek().isalnum() or self.peek() == '_':
            self.advance()
        return self.source[start:self.pos]

    def read_number(self) -> str:
        start = self.pos
        while self.peek().isdigit() or self.peek() == '.':
            self.advance()
        return self.source[start:self.pos]

    def read_string(self) -> str:
        quote = self.advance()
        result = quote
        while self.peek() != '\0' and self.peek() != quote:
            if self.peek() == '\\':
                result += self.advance()
            result += self.advance()
        if self.peek() == quote:
            result += self.advance()
        return result

    def tokens(self) -> List[Token]:
        result = []
        while self.pos < len(self.source):
            ch = self.peek()
            if ch in ' \t\r':
                self.skip_whitespace()
                continue
            if ch == '\n':
                result.append(Token(TokenType.NEWLINE, '\n', self.line, self.col))
                self.advance()
                continue
            if ch == '/' and self.peek(1) == '/':
                while self.peek() not in '\n\0':
                    self.advance()
                continue

            # String
            if ch == '"':
                result.append(Token(TokenType.STRING, self.read_string(), self.line, self.col))
                continue

            # Number
            if ch.isdigit() or (ch == '.' and self.peek(1).isdigit()):
                result.append(Token(TokenType.NUMBER, self.read_number(), self.line, self.col))
                continue

            # Identifier/Keyword
            if ch.isalpha() or ch == '_':
                ident = self.read_identifier()
                ident_lower = ident.lower()
                if ident_lower in KEYWORDS:
                    result.append(Token(KEYWORDS[ident_lower], ident, self.line, self.col))
                else:
                    result.append(Token(TokenType.IDENTIFIER, ident, self.line, self.col))
                continue

            # Boolean literals
            if ident := self.read_identifier() if self.peek().isalpha() else '':
                if ident in ('TRUE', 'FALSE'):
                    result.append(Token(TokenType.BOOL, ident, self.line, self.col))
                    continue

            # Operators
            for op, tok_type in OP_SYMS.items():
                if self.source.startswith(op, self.pos):
                    result.append(Token(tok_type, op, self.line, self.col))
                    self.pos += len(op)
                    self.col += len(op)
                    break
            else:
                raise ParseError(f"Unexpected char '{ch}' at line {self.line}")

        result.append(Token(TokenType.EOF, '', self.line, self.col))
        return result


# ============================================================================
# Parser
# ============================================================================

@dataclass
class ASTNode:
    pass


@dataclass
class ParamDef(ASTNode):
    name: str
    type_str: str
    default: Optional[Any]


@dataclass
class RunBlock(ASTNode):
    commands: List[str]


@dataclass
class SuccessCase(ASTNode):
    name: str
    expr: 'Expr'


@dataclass
class TaskDef(ASTNode):
    name: str
    params: List[ParamDef]
    run: Optional[RunBlock]
    success: Dict[str, Any]
    requires: 'Expr'
    output: Optional[str]
    timeout: Optional[float]


@dataclass
class Program(ASTNode):
    tasks: Dict[str, TaskDef]


# Expressions
@dataclass
class Expr(ASTNode):
    pass


@dataclass
class LiteralExpr(Expr):
    value: Any


@dataclass
class VarExpr(Expr):
    name: str


@dataclass
class BinOpExpr(Expr):
    op: str
    left: Expr
    right: Expr


@dataclass
class UnOpExpr(Expr):
    op: str
    operand: Expr


@dataclass
class FuncCallExpr(Expr):
    name: str
    args: List[Any]
    kwargs: Dict[str, Any]


@dataclass
class IndexExpr(Expr):
    target: Expr
    index: Expr


@dataclass
class ConcatExpr(Expr):
    left: Expr
    right: Expr


@dataclass
class AssignStmt(ASTNode):
    name: str
    value: Expr


@dataclass
class ForLoop(ASTNode):
    init: AssignStmt
    condition: Expr
    update: Expr
    body: List[Any]


@dataclass
class WhileLoop(ASTNode):
    condition: Expr
    body: List[Any]


@dataclass
class IfBranch(ASTNode):
    condition: Expr
    body: List[Any]


@dataclass
class IfStatement(ASTNode):
    branches: List[IfBranch]


@dataclass
class ReturnStmt(ASTNode):
    value: Expr


@dataclass
class Block(ASTNode):
    stmts: List[Any]


@dataclass
class TaskCallExpr(Expr):
    name: str
    args: List[Expr]
    kwargs: Dict[str, Any]


class Parser:
    def __init__(self, tokens: List[Token]):
        self.tokens = tokens
        self.pos = 0

    def peek(self, offset=0) -> Token:
        p = self.pos + offset
        return self.tokens[p] if p < len(self.tokens) else self.tokens[-1]

    def advance(self) -> Token:
        tok = self.peek()
        self.pos += 1
        return tok

    def expect(self, tok_type: TokenType, value: str = None) -> Token:
        tok = self.advance()
        if tok.type != tok_type:
            raise ParseError(f"Expected {tok_type.name}, got {tok.type.name}")
        if value and tok.value != value:
            raise ParseError(f"Expected '{value}', got '{tok.value}'")
        return tok

    def parse_program(self) -> Program:
        tasks = {}
        while self.peek().type != TokenType.EOF:
            if self.peek().type == TokenType.TASK:
                t = self.parse_task()
                tasks[t.name] = t
            else:
                raise ParseError(f"Unexpected {self.peek()}")
        return Program(tasks)

    def parse_task(self) -> TaskDef:
        self.expect(TokenType.TASK)
        name = self.expect(TokenType.IDENTIFIER).value

        params = []
        if self.peek().type == TokenType.PARAMS:
            self.expect(TokenType.PARAMS)
            self.expect(TokenType.LBRACE)
            params = self.parse_params()
            self.expect(TokenType.RBRACE)

        run = None
        if self.peek().type == TokenType.RUN:
            run = self.parse_run()

        success = {}
        if self.peek().type == TokenType.SUCCESS:
            self.expect(TokenType.SUCCESS)
            self.expect(TokenType.LBRACE)
            while self.peek().type == TokenType.IDENTIFIER:
                name = self.advance().value
                self.expect(TokenType.LBRACE)
                expr = self.parse_expr()
                self.expect(TokenType.RBRACE)
                success[name] = expr
            self.expect(TokenType.RBRACE)

        requires = None
        if self.peek().type == TokenType.REQUIRES:
            self.expect(TokenType.REQUIRES)
            requires = self.parse_expr()

        output = None
        if self.peek().type == TokenType.OUTPUT:
            self.expect(TokenType.OUTPUT)
            output = self.expect(TokenType.STRING).value.strip('"')

        timeout = None
        if self.peek().type == TokenType.TIMEOUT:
            self.expect(TokenType.TIMEOUT)
            timeout = float(self.expect(TokenType.NUMBER).value)

        return TaskDef(name, params, run, success, requires, output, timeout)

    def parse_params(self) -> List[ParamDef]:
        params = []
        while self.peek().type == TokenType.IDENTIFIER:
            name = self.advance().value
            self.expect(TokenType.COLON)
            type_str = self.expect(TokenType.IDENTIFIER).value
            default = None
            if self.peek().type == TokenType.ASSIGN:
                self.advance()
                default = self.parse_literal()
            if self.peek().type == TokenType.SEMI:
                self.advance()
            params.append(ParamDef(name, type_str, default))
        return params

    def parse_run(self) -> RunBlock:
        self.expect(TokenType.RUN)
        self.expect(TokenType.LBRACE)
        commands = []
        while self.peek().type != TokenType.RBRACE:
            cmd = self.read_command()
            if cmd.strip():
                commands.append(cmd.strip())
        self.expect(TokenType.RBRACE)
        return RunBlock(commands)

    def read_command(self) -> str:
        start = self.pos
        brace_depth = 0
        while self.pos < len(self.tokens):
            tok = self.peek()
            if tok.type == TokenType.LBRACE:
                brace_depth += 1
            elif tok.type == TokenType.RBRACE:
                if brace_depth == 0:
                    break
                brace_depth -= 1
            self.pos += 1
        end = self.pos
        return ''.join(t.value for t in self.tokens[start:end]).strip()

    def parse_expr(self) -> Expr:
        return self.parse_or()

    def parse_or(self) -> Expr:
        left = self.parse_and()
        while self.peek().type == TokenType.OR:
            self.advance()
            right = self.parse_and()
            left = BinOpExpr('||', left, right)
        return left

    def parse_and(self) -> Expr:
        left = self.parse_cmp()
        while self.peek().type == TokenType.AND:
            self.advance()
            right = self.parse_cmp()
            left = BinOpExpr('&&', left, right)
        return left

    def parse_cmp(self) -> Expr:
        left = self.parse_add()
        while self.peek().type in (TokenType.EQ, TokenType.NEQ,
                                    TokenType.LT, TokenType.GT,
                                    TokenType.LTE, TokenType.GTE):
            op = self.advance().value
            right = self.parse_add()
            left = BinOpExpr(op, left, right)
        return left

    def parse_add(self) -> Expr:
        left = self.parse_mul()
        while self.peek().type in (TokenType.PLUS, TokenType.MINUS):
            op = self.advance().value
            right = self.parse_mul()
            left = BinOpExpr(op, left, right)
        return left

    def parse_mul(self) -> Expr:
        left = self.parse_unary()
        while self.peek().type in (TokenType.MULT, TokenType.DIV, TokenType.MOD):
            op = self.advance().value
            right = self.parse_unary()
            left = BinOpExpr(op, left, right)
        return left

    def parse_unary(self) -> Expr:
        if self.peek().type == TokenType.NOT:
            self.advance()
            return UnOpExpr('!', self.parse_unary())
        if self.peek().type in (TokenType.PLUS, TokenType.MINUS):
            op = self.advance().value
            return UnOpExpr(op, self.parse_unary())
        return self.parse_primary()

    def parse_primary(self) -> Expr:
        tok = self.peek()

        if tok.type == TokenType.LPAREN:
            self.advance()
            expr = self.parse_expr()
            self.expect(TokenType.RPAREN)
            return expr

        if tok.type == TokenType.BOOL:
            self.advance()
            return LiteralExpr(tok.value == 'TRUE')

        if tok.type == TokenType.NUMBER:
            self.advance()
            val = tok.value
            if '.' in val:
                return LiteralExpr(float(val))
            return LiteralExpr(int(val))

        if tok.type == TokenType.STRING:
            self.advance()
            return LiteralExpr(tok.value.strip('"'))

        if tok.type == TokenType.IDENTIFIER:
            ident = self.advance().value

            if self.peek().type == TokenType.LPAREN:
                return self.parse_func_call(ident)

            if self.peek().type == TokenType.LBRACK:
                return self.parse_index(ident)

            return VarExpr(ident)

        raise ParseError(f"Unexpected {tok}")

    def parse_func_call(self, name: str) -> FuncCallExpr:
        self.expect(TokenType.LPAREN)
        args = []
        kwargs = {}
        while self.peek().type != TokenType.RPAREN:
            arg = self.parse_arg()
            if isinstance(arg, tuple):
                kwargs[arg[0]] = arg[1]
            else:
                args.append(arg)
            if self.peek().type == TokenType.COMMA:
                self.advance()
        self.expect(TokenType.RPAREN)
        return FuncCallExpr(name, args, kwargs)

    def parse_arg(self) -> Any:
        if self.peek().type == TokenType.IDENTIFIER and self.peek(1).type == TokenType.EQ:
            name = self.advance().value
            self.expect(TokenType.EQ)
            return (name, self.parse_expr())
        return self.parse_expr()

    def parse_index(self, name: str) -> IndexExpr:
        self.expect(TokenType.LBRACK)
        idx = self.parse_expr()
        self.expect(TokenType.RBRACK)
        return IndexExpr(VarExpr(name), idx)

    def parse_literal(self) -> Any:
        tok = self.peek()
        if tok.type in (TokenType.BOOL,):
            self.advance()
            return tok.value == 'TRUE'
        if tok.type == TokenType.NUMBER:
            self.advance()
            val = tok.value
            return float(val) if '.' in val else int(val)
        if tok.type == TokenType.STRING:
            self.advance()
            return tok.value.strip('"')
        raise ParseError(f"Expected literal, got {tok}")

