#!/usr/bin/env python3
"""
Pipeline Executor CLI
Executes pipelines from .pipe files and optional TOML config files.
"""

import json
import os
import re
import subprocess
import sys
import time
from abc import ABC, abstractmethod
from dataclasses import dataclass, field
from enum import Enum
from typing import Any, Dict, List, Optional, Union

# Optional: toml for config parsing
try:
    import toml
except ImportError:
    toml = None


# ============================================================================
# Data Structures
# ============================================================================

class TokenType(Enum):
    KEYWORD = "KEYWORD"
    IDENTIFIER = "IDENTIFIER"
    LITERAL_STRING = "LITERAL_STRING"
    LITERAL_INT = "LITERAL_INT"
    LITERAL_FLOAT = "LITERAL_FLOAT"
    LITERAL_BOOL = "LITERAL_BOOL"
    OPERATOR = "OPERATOR"
    PUNCTUATION = "PUNCTUATION"
    DELIMITER = "DELIMITER"
    COMMENT = "COMMENT"
    WHITESPACE = "WHITESPACE"
    EOF = "EOF"


@dataclass
class Token:
    type: TokenType
    value: str
    line: int
    column: int

    def __repr__(self):
        return f"Token({self.type.value}, {repr(self.value)})"


@dataclass
class Position:
    line: int
    column: int


# ============================================================================
# Lexer (Tokenizer)
# ============================================================================

class Lexer:
    """Tokenizes the pipeline DSL source code."""

    KEYWORDS = {
        "task", "params", "run", "success", "requires", "output", "timeout",
        "for", "while", "if", "elif", "else", "return", "break", "continue",
        "TRUE", "FALSE", "fails", "len", "contains", "equals", "exists",
        "in", "int", "float", "bool", "string", "list", "exit", "code",
        "stdout", "stderr", "file"
    }

    OPERATORS = {
        "+", "-", "*", "/", "%", "==", "!=", "<", ">", "<=", ">=",
        "=", "!", "&&", "||", "", ";", "", ",", "."
    }

    PUNCTUATION = {
        "{", "}", "(", ")", "[", "]", ":", ";", "=", "%"
    }

    def __init__(self, source: str):
        self.source = source
        self.position = 0
        self.line = 1
        self.column = 1
        self.tokens: List[Token] = []

    def peek(self, offset: int = 0) -> str:
        """Peek at the next character without consuming it."""
        pos = self.position + offset
        if pos >= len(self.source):
            return '\0'
        return self.source[pos]

    def advance(self) -> str:
        """Consume and return the next character."""
        char = self.peek()
        if char == '\n':
            self.line += 1
            self.column = 1
        else:
            self.column += 1
        self.position += 1
        return char

    def skip_whitespace(self):
        """Skip whitespace characters."""
        while self.peek() in ' \t\r\n':
            self.advance()

    def read_identifier(self) -> str:
        """Read an identifier or keyword."""
        start = self.position
        while self.peek().isalnum() or self.peek() == '_':
            self.advance()
        return self.source[start:self.position]

    def read_number(self) -> str:
        """Read a number (int or float)."""
        start = self.position
        has_decimal = False
        while self.peek().isdigit() or self.peek() == '.':
            if self.peek() == '.':
                if has_decimal:
                    break
                has_decimal = True
            self.advance()
        return self.source[start:self.position]

    def read_string(self) -> str:
        """Read a string literal."""
        quote = self.advance()  # Consume opening quote
        result = quote
        while self.peek() != '\0' and self.peek() != quote:
            if self.peek() == '\\':
                result += self.advance()  # Add escape char
            result += self.advance()
        if self.peek() == quote:
            result += self.advance()
        return result

    def tokenize(self) -> List[Token]:
        """Convert source code to tokens."""
        while self.position < len(self.source):
            char = self.peek()

            # Skip whitespace
            if char in ' \t\r':
                self.advance()
                continue

            # Newline
            if char == '\n':
                self.advance()
                continue

            # Comments
            if char == '/' and self.peek(1) == '/':
                while self.peek() not in '\n\0':
                    self.advance()
                continue

            # String literals
            if char == '"':
                start = self.position
                result = self.read_string()
                self.tokens.append(Token(
                    TokenType.LITERAL_STRING,
                    result,
                    self.line,
                    self.column
                ))
                continue

            # Numbers
            if char.isdigit():
                start = self.position
                value = self.read_number()
                token_type = TokenType.LITERAL_INT
                if '.' in value:
                    token_type = TokenType.LITERAL_FLOAT
                self.tokens.append(Token(token_type, value, self.line, self.column))
                continue

            # Identifiers
            if char.isalpha() or char == '_':
                value = self.read_identifier()
                if value.upper() in self.KEYWORDS:
                    self.tokens.append(Token(TokenType.KEYWORD, value, self.line, self.column))
                else:
                    self.tokens.append(Token(TokenType.IDENTIFIER, value, self.line, self.column))
                continue

            # Operators and punctuation
            if char in '!%=+-<>&|.,':
                # Check for two-character operators
                two_char = char + self.peek(1)
                if two_char in self.OPERATORS:
                    self.tokens.append(Token(TokenType.OPERATOR, two_char, self.line, self.column))
                    self.advance()
                    self.advance()
                    continue
                if char in self.OPERATORS:
                    self.tokens.append(Token(TokenType.OPERATOR, char, self.line, self.column))
                    self.advance()
                    continue

            if char in '{}()[];:,':
                self.tokens.append(Token(TokenType.PUNCTUATION, char, self.line, self.column))
                self.advance()
                continue

            # Unknown character
            raise SyntaxError(f"Unknown character '{char}' at line {self.line}, column {self.column}")

        self.tokens.append(Token(TokenType.EOF, '', self.line, self.column))
        return self.tokens


# ============================================================================
# AST Nodes
# ============================================================================

@dataclass
class ASTNode:
    """Base class for AST nodes."""
    pass


@dataclass
class ParameterDef(ASTNode):
    name: str
    type: str
    default: Optional[Any] = None


@dataclass
class Task(ASTNode):
    name: str
    params: List[ParameterDef]
    run: Optional[List[str]]
    success: Optional[Dict[str, 'Expression']]
    requires: Optional['Expression']
    output: Optional[str]
    timeout: Optional[float]


@dataclass
class Expression(ASTNode):
    """Base class for expressions."""
    pass


@dataclass
class Literal(Expression):
    value: Any
    type: str


@dataclass
class UnaryOp(Expression):
    op: str
    operand: Expression


@dataclass
class BinaryOp(Expression):
    left: Expression
    op: str
    right: Expression


@dataclass
class Identifier(Expression):
    name: str


@dataclass
class Assign(Expression):
    name: str
    value: Expression


@dataclass
class ForLoop(Expression):
    init: Optional[Assign]
    condition: Optional[Expression]
    increment: Optional[Expression]
    body: List[Expression]


@dataclass
class WhileLoop(Expression):
    condition: Expression
    body: List[Expression]


@dataclass
class IfBranch(ASTNode):
    condition: Optional[Expression]
    body: List[Expression]


@dataclass
class IfStatement(Expression):
    branches: List[IfBranch]


@dataclass
class ReturnStmt(Expression):
    value: Optional[Expression]


@dataclass
class BreakStmt(Expression):
    pass


@dataclass
class ContinueStmt(Expression):
    pass


@dataclass
class FunctionCall(Expression):
    name: str
    args: List[Expression]
    kwargs: Dict[str, Expression]


@dataclass
class IndexExpr(Expression):
    array: Expression
    index: Expression


@dataclass
class ConcatExpr(Expression):
    left: Expression
    right: Expression


@dataclass
class TaskCall(Expression):
    name: str
    args: List[Expression]
    kwargs: Dict[str, Expression]


@dataclass
class Block(Expression):
    statements: List[Expression]


# ============================================================================
# Parser
# ============================================================================

class Parser:
    """Parses tokens into AST."""

    def __init__(self, tokens: List[Token]):
        self.tokens = tokens
        self.position = 0

    def peek(self, offset: int = 0) -> Token:
        pos = self.position + offset
        if pos >= len(self.tokens):
            return self.tokens[-1]
        return self.tokens[pos]

    def advance(self) -> Token:
        token = self.peek()
        self.position += 1
        return token

    def expect(self, token_type: TokenType, value: Optional[str] = None) -> Token:
        token = self.advance()
        if token.type != token_type:
            raise SyntaxError(f"Expected {token_type.value}, got {token.type.value}")
        if value and token.value != value:
            raise SyntaxError(f"Expected '{value}', got '{token.value}'")
        return token

    def parse_pipeline(self) -> List[Task]:
        """Parse the entire pipeline file."""
        tasks = []
        while self.peek().type != TokenType.EOF:
            if self.peek().type == TokenType.KEYWORD and self.peek().value == "task":
                task = self.parse_task()
                tasks.append(task)
            else:
                raise SyntaxError(f"Unexpected token: {self.peek()}")
        return tasks

    def parse_task(self) -> Task:
        """Parse a task definition."""
        self.expect(TokenType.KEYWORD, "task")
        name = self.expect(TokenType.IDENTIFIER).value

        # Parse params block
        params = []
        if self.peek().type == TokenType.KEYWORD and self.peek().value == "params":
            self.expect(TokenType.KEYWORD, "params")
            self.expect(TokenType.PUNCTUATION, "{")
            params = self.parse_params()
            self.expect(TokenType.PUNCTUATION, "}")

        # Parse run block
        run = None
        if self.peek().type == TokenType.KEYWORD and self.peek().value == "run":
            run = self.parse_run()

        # Parse success block
        success = None
        if self.peek().type == TokenType.KEYWORD and self.peek().value == "success":
            success = self.parse_success()

        # Parse requires block
        requires = None
        if self.peek().type == TokenType.KEYWORD and self.peek().value == "requires":
            requires = self.parse_expression_block()

        # Parse output
        output = None
        if self.peek().type == TokenType.KEYWORD and self.peek().value == "output":
            self.expect(TokenType.KEYWORD, "output")
            output_token = self.expect(TokenType.LITERAL_STRING)
            output = output_token.value.strip('"')

        # Parse timeout
        timeout = None
        if self.peek().type == TokenType.KEYWORD and self.peek().value == "timeout":
            self.expect(TokenType.KEYWORD, "timeout")
            timeout_token = self.expect(TokenType.LITERAL_INT)
            timeout = float(timeout_token.value)

        return Task(name, params, run, success, requires, output, timeout)

    def parse_params(self) -> List[ParameterDef]:
        """Parse parameter definitions."""
        params = []
        while True:
            # Check for comma or closing brace
            if self.peek().type == TokenType.PUNCTUATION:
                if self.peek().value == '}':
                    break
                if self.peek().value == ',':
                    self.advance()
                    continue

            # Parse parameter
            name = self.expect(TokenType.IDENTIFIER).value
            self.expect(TokenType.PUNCTUATION, ":")

            # Type
            type_token = self.expect(TokenType.IDENTIFIER)
            type_name = type_token.value

            # Optional default value
            default = None
            if self.peek().type == TokenType.OPERATOR and self.peek().value == '=':
                self.advance()
                default = self.parse_literal()

            # Optional semicolon
            if self.peek().type == TokenType.PUNCTUATION and self.peek().value == ';':
                self.advance()

            params.append(ParameterDef(name, type_name, default))

        return params

    def parse_run(self) -> List[str]:
        """Parse run block (list of commands)."""
        self.expect(TokenType.KEYWORD, "run")
        self.expect(TokenType.PUNCTUATION, "{")

        commands = []
        while not (self.peek().type == TokenType.PUNCTUATION and self.peek().value == '}'):
            if self.peek().type == TokenType.EOF:
                raise SyntaxError("Unterminated run block")

            # Read until closing brace
            start = self.position
            brace_count = 0
            while not (self.peek().type == TokenType.PUNCTUATION and
                      self.peek().value == '}' and brace_count == 0):
                if self.peek().type == TokenType.PUNCTUATION:
                    if self.peek().value == '{':
                        brace_count += 1
                    elif self.peek().value == '}':
                        brace_count -= 1
                self.advance()

            # Extract the command text
            cmd_text = ''
            pos = start
            while pos < self.position:
                cmd_text += self.tokens[pos].value
                pos += 1

            # Clean up the command text
            cmd_text = cmd_text.strip()
            if cmd_text:
                commands.append(cmd_text)

            self.expect(TokenType.PUNCTUATION, "}")

        self.advance()  # Consume }
        return commands

    def parse_success(self) -> Dict[str, Expression]:
        """Parse success block."""
        self.expect(TokenType.KEYWORD, "success")
        self.expect(TokenType.PUNCTUATION, "{")

        success_conditions = {}
        while True:
            if self.peek().type == TokenType.PUNCTUATION:
                if self.peek().value == '}':
                    break

            # Parse condition name
            name = self.expect(TokenType.IDENTIFIER).value
            self.expect(TokenType.PUNCTUATION, "{")

            # Parse the expression block
            expr = self.parse_expression_block()

            success_conditions[name] = expr
            self.expect(TokenType.PUNCTUATION, "}")

        self.expect(TokenType.PUNCTUATION, "}")
        return success_conditions

    def parse_expression_block(self) -> Expression:
        """Parse an expression block (either {} wrapped or single expression)."""
        if self.peek().type == TokenType.PUNCTUATION and self.peek().value == '{':
            self.advance()  # Consume {
            block = Block([])
            while not (self.peek().type == TokenType.PUNCTUATION and self.peek().value == '}'):
                if self.peek().type == TokenType.EOF:
                    raise SyntaxError("Unterminated block")
                stmt = self.parse_statement()
                block.statements.append(stmt)
            self.advance()  # Consume }
            return block
        else:
            return self.parse_statement()

    def parse_statement(self) -> Expression:
        """Parse a statement."""
        token = self.peek()

        if token.type == TokenType.KEYWORD:
            if token.value == "for":
                return self.parse_for_loop()
            elif token.value == "while":
                return self.parse_while_loop()
            elif token.value == "if":
                return self.parse_if_statement()
            elif token.value == "return":
                return self.parse_return()
            elif token.value == "break":
                self.advance()
                return BreakStmt()
            elif token.value == "continue":
                self.advance()
                return ContinueStmt()
            elif token.type == TokenType.IDENTIFIER and self.peek(1).type == TokenType.PUNCTUATION:
                if self.peek(1).value == '(':
                    return self.parse_task_call()
            elif token.type == TokenType.IDENTIFIER and self.peek(1).type == TokenType.OPERATOR:
                if self.peek(1).value == '=':
                    return self.parse_assignment()

        # Try to parse as function call or expression
        return self.parse_expression()

    def parse_assignment(self) -> Assign:
        """Parse an assignment statement."""
        name = self.expect(TokenType.IDENTIFIER).value
        self.expect(TokenType.OPERATOR, "=")
        value = self.parse_expression()
        return Assign(name, value)

    def parse_for_loop(self) -> ForLoop:
        """Parse a for loop."""
        self.expect(TokenType.KEYWORD, "for")
        self.expect(TokenType.PUNCTUATION, "(")

        # Parse init, condition, increment
        init = None
        if not (self.peek().type == TokenType.PUNCTUATION and self.peek().value == ';'):
            init = self.parse_assignment() if self.peek().type == TokenType.IDENTIFIER else self.parse_expression()

        self.expect(TokenType.PUNCTUATION, ";")
        condition = None
        if not (self.peek().type == TokenType.PUNCTUATION and self.peek().value == ';'):
            condition = self.parse_expression()

        self.expect(TokenType.PUNCTUATION, ";")
        increment = None
        if not (self.peek().type == TokenType.PUNCTUATION and self.peek().value == ')'):
            increment = self.parse_expression()

        self.expect(TokenType.PUNCTUATION, ")")
        self.expect(TokenType.PUNCTUATION, "{")

        body = []
        while not (self.peek().type == TokenType.PUNCTUATION and self.peek().value == '}'):
            body.append(self.parse_statement())

        self.expect(TokenType.PUNCTUATION, "}")

        return ForLoop(init, condition, increment, body)

    def parse_while_loop(self) -> WhileLoop:
        """Parse a while loop."""
        self.expect(TokenType.KEYWORD, "while")
        self.expect(TokenType.PUNCTUATION, "(")
        condition = self.parse_expression()
        self.expect(TokenType.PUNCTUATION, ")")
        self.expect(TokenType.PUNCTUATION, "{")

        body = []
        while not (self.peek().type == TokenType.PUNCTUATION and self.peek().value == '}'):
            body.append(self.parse_statement())

        self.expect(TokenType.PUNCTUATION, "}")

        return WhileLoop(condition, body)

    def parse_if_statement(self) -> IfStatement:
        """Parse an if/elif/else statement."""
        branches = []

        while token.type == TokenType.KEYWORD and token.value in ["if", "elif"]:
            is_if = token.value == "if"
            self.advance()
            self.expect(TokenType.PUNCTUATION, "(")
            condition = self.parse_expression()
            self.expect(TokenType.PUNCTUATION, ")")
            self.expect(TokenType.PUNCTUATION, "{")

            body = []
            while not (self.peek().type == TokenType.PUNCTUATION and self.peek().value == '}'):
                body.append(self.parse_statement())

            self.expect(TokenType.PUNCTUATION, "}")
            branches.append(IfBranch(condition, body))

            if not is_if:
                break  # Can only have one elif

        # Check for else
        if self.peek().type == TokenType.KEYWORD and self.peek().value == "else":
            self.advance()
            self.expect(TokenType.PUNCTUATION, "{")

            body = []
            while not (self.peek().type == TokenType.PUNCTUATION and self.peek().value == '}'):
                body.append(self.parse_statement())

            self.expect(TokenType.PUNCTUATION, "}")
            branches.append(IfBranch(None, body))

        return IfStatement(branches)

    def parse_return(self) -> ReturnStmt:
        """Parse a return statement."""
        self.expect(TokenType.KEYWORD, "return")
        if not (self.peek().type == TokenType.PUNCTUATION and self.peek().value == ';'):
            return ReturnStmt(self.parse_expression())
        return ReturnStmt(None)

    def parse_task_call(self) -> TaskCall:
        """Parse a task call expression."""
        name = self.expect(TokenType.IDENTIFIER).value

        args = []
        kwargs = {}

        if self.peek().type == TokenType.PUNCTUATION and self.peek().value == '(':
            self.advance()

            # Parse arguments
            while not (self.peek().type == TokenType.PUNCTUATION and self.peek().value == ')'):
                # Check if this is a keyword argument
                if self.peek().type == TokenType.IDENTIFIER and self.peek(1).type == TokenType.PUNCTUATION:
                    if self.peek(1).value == '=':
                        kw_name = self.advance().value
                        self.advance()  # Consume =
                        kw_value = self.parse_expression()
                        kwargs[kw_name] = kw_value
                    else:
                        # Positional argument
                        arg_value = self.parse_expression()
                        args.append(arg_value)
                else:
                    arg_value = self.parse_expression()
                    args.append(arg_value)

                if self.peek().type == TokenType.PUNCTUATION and self.peek().value == ',':
                    self.advance()

            self.expect(TokenType.PUNCTUATION, ")")

        return TaskCall(name, args, kwargs)

    def parse_expression(self) -> Expression:
        """Parse an expression."""
        return self.parse_logical_or()

    def parse_logical_or(self) -> Expression:
        """Parse logical OR expressions."""
        left = self.parse_logical_and()
        while self.peek().type == TokenType.OPERATOR and self.peek().value == '||':
            self.advance()
            right = self.parse_logical_and()
            left = BinaryOp(left, '||', right)
        return left

    def parse_logical_and(self) -> Expression:
        """Parse logical AND expressions."""
        left = self.parse_equality()
        while self.peek().type == TokenType.OPERATOR and self.peek().value == '&&':
            self.advance()
            right = self.parse_equality()
            left = BinaryOp(left, '&&', right)
        return left

    def parse_equality(self) -> Expression:
        """Parse equality expressions."""
        left = self.parse_comparison()
        while self.peek().type == TokenType.OPERATOR and self.peek().value in ['==', '!=']:
            op = self.advance().value
            right = self.parse_comparison()
            left = BinaryOp(left, op, right)
        return left

    def parse_comparison(self) -> Expression:
        """Parse comparison expressions."""
        left = self.parse_additive()
        while self.peek().type == TokenType.OPERATOR and self.peek().value in ['<', '>', '<=', '>=']:
            op = self.advance().value
            right = self.parse_additive()
            left = BinaryOp(left, op, right)
        return left

    def parse_additive(self) -> Expression:
        """Parse addition/subtraction expressions."""
        left = self.parse_multiplicative()
        while self.peek().type == TokenType.OPERATOR and self.peek().value in ['+', '-']:
            op = self.advance().value
            right = self.parse_multiplicative()
            left = BinaryOp(left, op, right)
        return left

    def parse_multiplicative(self) -> Expression:
        """Parse multiplication/division expressions."""
        left = self.parse_unary()
        while self.peek().type == TokenType.OPERATOR and self.peek().value in ['*', '/', '%']:
            op = self.advance().value
            right = self.parse_unary()
            left = BinaryOp(left, op, right)
        return left

    def parse_unary(self) -> Expression:
        """Parse unary expressions."""
        if self.peek().type == TokenType.OPERATOR and self.peek().value == '!':
            self.advance()
            operand = self.parse_unary()
            return UnaryOp('!', operand)
        if self.peek().type == TokenType.OPERATOR and self.peek().value in ['+', '-']:
            op = self.advance().value
            operand = self.parse_unary()
            return UnaryOp(op, operand)
        return self.parse_primary()

    def parse_primary(self) -> Expression:
        """Parse primary expressions."""
        token = self.peek()

        # Function call: func(args)
        if token.type == TokenType.IDENTIFIER and self.peek(1).type == TokenType.PUNCTUATION:
            if self.peek(1).value == '(':
                return self.parse_function_call()

        # Parentheses
        if token.type == TokenType.PUNCTUATION and token.value == '(':
            self.advance()
            expr = self.parse_expression()
            self.expect(TokenType.PUNCTUATION, ')')
            return expr

        # String literal
        if token.type == TokenType.LITERAL_STRING:
            self.advance()
            value = token.value.strip('"')
            # Unescape
            value = self.unescape_string(value)
            return Literal(value, "string")

        # Boolean literal
        if token.type == TokenType.KEYWORD and token.value.upper() == "TRUE":
            self.advance()
            return Literal(True, "bool")
        if token.type == TokenType.KEYWORD and token.value.upper() == "FALSE":
            self.advance()
            return Literal(False, "bool")

        # Number literal
        if token.type in [TokenType.LITERAL_INT, TokenType.LITERAL_FLOAT]:
            self.advance()
            value = token.value
            if '.' in value:
                return Literal(float(value), "float")
            return Literal(int(value), "int")

        # Identifier
        if token.type == TokenType.IDENTIFIER:
            self.advance()
            return Identifier(token.value)

        raise SyntaxError(f"Unexpected token in expression: {token}")

    def parse_function_call(self) -> FunctionCall:
        """Parse a function call."""
        name = self.expect(TokenType.IDENTIFIER).value
        args = []
        kwargs = {}

        self.expect(TokenType.PUNCTUATION, "(")

        while not (self.peek().type == TokenType.PUNCTUATION and self.peek().value == ')'):
            # Check if this is a keyword argument
            if self.peek().type == TokenType.IDENTIFIER and self.peek(1).type == TokenType.PUNCTUATION:
                if self.peek(1).value == '=':
                    kw_name = self.advance().value
                    self.advance()  # Consume =
                    kw_value = self.parse_expression()
                    kwargs[kw_name] = kw_value
                else:
                    arg = self.parse_expression()
                    args.append(arg)
            else:
                arg = self.parse_expression()
                args.append(arg)

            if self.peek().type == TokenType.PUNCTUATION and self.peek().value == ',':
                self.advance()

        self.expect(TokenType.PUNCTUATION, ")")
        return FunctionCall(name, args, kwargs)

    def unescape_string(self, s: str) -> str:
        """Unescape string literals."""
        s = s.replace('\\n', '\n')
        s = s.replace('\\t', '\t')
        s = s.replace('\\"', '"')
        s = s.replace('\\\\', '\\')
        return s


# ============================================================================
# Expression Interpreter
# ============================================================================

class Interpreter:
    """Interprets expressions in the context of task execution."""

    def __init__(self, tasks: Dict[str, Task], params: Dict[str, Any],
                 workspace: str, output_dir: str, job_context: Dict = None):
        self.tasks = tasks
        self.params = params
        self.workspace = workspace
        self.output_dir = output_dir
        self.job_context = job_context or {}
        self.task_results: Dict[str, bool] = {}
        self.variables: Dict[str, Any] = {}

    def evaluate(self, expr: Expression) -> Any:
        """Evaluate an expression and return its value."""
        if isinstance(expr, Literal):
            return expr.value
        elif isinstance(expr, Identifier):
            # Check variables first
            if expr.name in self.variables:
                return self.variables[expr.name]
            # Check params
            if expr.name in self.params:
                return self.params[expr.name]
            return False  # Unknown identifier
        elif isinstance(expr, BinaryOp):
            left = self.evaluate(expr.left)
            right = self.evaluate(expr.right)

            if expr.op == '+':
                return left + right
            elif expr.op == '-':
                return left - right
            elif expr.op == '*':
                return left * right
            elif expr.op == '/':
                return left / right
            elif expr.op == '%':
                return left % right
            elif expr.op == '==':
                return left == right
            elif expr.op != '=':
                return left != right
            elif expr.op == '<':
                return left < right
            elif expr.op == '>':
                return left > right
            elif expr.op == '<=':
                return left <= right
            elif expr.op == '>=':
                return left >= right
            elif expr.op == '&&':
                return left and right
            elif expr.op == '||':
                return left or right
        elif isinstance(expr, UnaryOp):
            operand = self.evaluate(expr.operand)
            if expr.op == '!':
                return not operand
            elif expr.op == '+':
                return +operand
            elif expr.op == '-':
                return -operand
        elif isinstance(expr, FunctionCall):
            return self.call_function(expr.name, expr.args, expr.kwargs)
        elif isinstance(expr, Block):
            return self.evaluate_block(expr)
        elif isinstance(expr, Assign):
            value = self.evaluate(expr.value)
            self.variables[expr.name] = value
            return value
        elif isinstance(expr, ForLoop):
            return self.evaluate_for_loop(expr)
        elif isinstance(expr, IfStatement):
            return self.evaluate_if_statement(expr)
        elif isinstance(expr, ReturnStmt):
            return self.evaluate(expr.value) if expr.value else None
        elif isinstance(expr, BreakStmt):
            raise BreakException()
        elif isinstance(expr, ContinueStmt):
            raise ContinueException()

        return None

    def evaluate_block(self, block: Block) -> Any:
        """Evaluate a block of statements."""
        for stmt in block.statements:
            try:
                result = self.evaluate(stmt)
                # If we encounter a return, propagate it
                if isinstance(stmt, ReturnStmt):
                    return result
            except (BreakException, ContinueException) as e:
                raise e
            except Exception as e:
                # Log and continue
                print(json.dumps({"event": "DEBUG", "message": str(e)}))
        return None

    def evaluate_for_loop(self, loop: ForLoop) -> Any:
        """Evaluate a for loop."""
        # Evaluate init
        if loop.init:
            self.evaluate(loop.init)

        while True:
            # Evaluate condition
            if loop.condition:
                condition = self.evaluate(loop.condition)
                if not condition:
                    break

            # Evaluate body
            try:
                for stmt in loop.body:
                    self.evaluate(stmt)
            except BreakException:
                break
            except ContinueException:
                pass

            # Evaluate increment
            if loop.increment:
                self.evaluate(loop.increment)

        return None

    def evaluate_if_statement(self, stmt: IfStatement) -> Any:
        """Evaluate an if statement."""
        for branch in stmt.branches:
            # If condition is None, this is an else branch
            if branch.condition is None:
                return self.evaluate_block(Block(branch.body))
            else:
                condition = self.evaluate(branch.condition)
                if condition:
                    return self.evaluate_block(Block(branch.body))
        return None

    def call_function(self, name: str, args: List[Expression], kwargs: Dict[str, Expression]) -> Any:
        """Call builtin or task functions."""

        # Built-in functions
        if name == "len":
            arr = self.evaluate(args[0])
            return len(arr) if isinstance(arr, list) else 0

        elif name == "contains":
            if len(args) < 2:
                return False
            file_or_stdout = self.evaluate(args[0])
            pattern = self.evaluate(args[1])

            # Check file, stdout, or stderr
            content = ""
            if isinstance(file_or_stdout, str):
                if file_or_stdout == "stdout":
                    content = self.job_context.get("stdout", "")
                elif file_or_stdout == "stderr":
                    content = self.job_context.get("stderr", "")
                else:
                    # File path
                    try:
                        abs_path = os.path.join(self.output_dir or self.workspace, file_or_stdout)
                        with open(abs_path, 'r') as f:
                            content = f.read()
                    except:
                        content = ""

            # Check for exact string or pattern
            if isinstance(pattern, str):
                return pattern in content
            return False

        elif name == "equals":
            if len(args) < 2:
                return False
            file_or_stdout = self.evaluate(args[0])
            expected = self.evaluate(args[1])

            content = ""
            if isinstance(file_or_stdout, str):
                if file_or_stdout == "stdout":
                    content = self.job_context.get("stdout", "")
                elif file_or_stdout == "stderr":
                    content = self.job_context.get("stderr", "")
                else:
                    try:
                        abs_path = os.path.join(self.output_dir or self.workspace, file_or_stdout)
                        with open(abs_path, 'r') as f:
                            content = f.read()
                    except:
                        content = ""

            return str(content).strip() == str(expected).strip()

        elif name == "exists":
            if len(args) < 1:
                return False
            filepath = self.evaluate(args[0])
            if isinstance(filepath, str):
                abs_path = os.path.join(self.output_dir or self.workspace, filepath)
                return os.path.exists(abs_path)
            return False

        elif name == "fails":
            if len(args) < 1:
                return False
            task_call = args[0]
            if isinstance(task_call, TaskCall):
                task_name = task_call.name
                # Return whether the task failed
                return not self.task_results.get(task_name, True)
            return False

        # Task calls
        elif name in self.tasks:
            # This is a task call that should have been evaluated earlier
            return self.task_results.get(name, False)

        return False


class BreakException(Exception):
    pass


class ContinueException(Exception):
    pass


# ============================================================================
# Task Executor
# ============================================================================

@dataclass
class JobContext:
    """Context for a running job."""
    job_id: int
    task: str
    params: Dict[str, Any]
    parent: Optional[int] = None
    stdout: str = ""
    stderr: str = ""
    exit_code: int = 0
    timed_out: bool = False
    success: Dict[str, bool] = field(default_factory=dict)
    output: Optional[str] = None
    duration: float = 0.0


class TaskExecutor:
    """Executes tasks and manages dependencies."""

    def __init__(self, tasks: List[Task], workspace: str, output_dir: str,
                 config: Dict = None, clean_cwd: bool = False):
        self.tasks = {t.name: t for t in tasks}
        self.workspace = workspace
        self.output_dir = output_dir
        self.config = config or {}
        self.clean_cwd = clean_cwd
        self.jobs: List[JobContext] = []
        self.job_counter = 0
        self.job_results: Dict[int, JobContext] = {}

    def run(self, entry_task: str, entry_params: Dict[str, Any] = None) -> int:
        """Run the pipeline starting from entry_task."""
        if entry_task not in self.tasks:
            return self.error("INVALID_PIPE", f"Entry task '{entry_task}' not found")

        # Start execution
        self.execute_task(entry_task, entry_params or {}, parent=None)

        # Check if entry task succeeded
        entry_job = self.job_results.get(1)
        if entry_job and entry_job.exit_code == 0:
            return 0
        return 1

    def execute_task(self, task_name: str, params: Dict[str, Any],
                     parent: Optional[int]) -> int:
        """Execute a task and return job_id."""
        self.job_counter += 1
        job_id = self.job_counter

        task = self.tasks[task_name]

        # Emit TASK_STARTED
        self.emit_event("TASK_STARTED", job_id, task_name, params, parent)

        # Create job context
        job = JobContext(
            job_id=job_id,
            task=task_name,
            params=params,
            parent=parent
        )

        start_time = time.time()

        try:
            # Resolve requires first
            if task.requires:
                # Create interpreter for requires
                interp = Interpreter(self.tasks, params, self.workspace, self.output_dir)
                interp.task_results = self.job_results

                # Evaluate requires
                result = interp.evaluate(task.requires)

                # Check if all required tasks succeeded
                if not result:
                    raise Exception("Requirements not satisfied")

            # Run the task
            if task.run:
                stdout, stderr, exit_code, timed_out = self.run_commands(
                    task.run, params, task.timeout
                )

                # Clean output
                stdout = self.clean_output(stdout)
                stderr = self.clean_output(stderr)

                job.stdout = stdout
                job.stderr = stderr
                job.exit_code = exit_code
                job.timed_out = timed_out

                # Check exit code
                if exit_code != 0:
                    raise Exception(f"Task exited with code {exit_code}")

            # Evaluate success criteria
            success_results = {}
            if task.success:
                for name, expr in task.success.items():
                    interp = Interpreter(
                        self.tasks, params, self.workspace,
                        self.output_dir, {
                            "stdout": job.stdout,
                            "stderr": job.stderr
                        }
                    )
                    interp.task_results = self.job_results
                    try:
                        result = interp.evaluate(expr)
                        success_results[name] = bool(result)
                    except Exception as e:
                        success_results[name] = False

            job.success = success_results

            # Determine overall success
            # If no success criteria, check exit code
            # If success criteria exist, all must pass
            if task.success and success_results:
                if not all(success_results.values()):
                    raise Exception("Success criteria not met")

            # Set output directory
            if task.output:
                job.output = self.resolve_path(task.output, params)

            job.exit_code = 0

        except Exception as e:
            job.exit_code = 1

        # Calculate duration
        job.duration = time.time() - start_time

        # Store job result
        self.job_results[job_id] = job

        # Emit TASK_COMPLETED or TASK_FAILED
        event = "TASK_COMPLETED" if job.exit_code == 0 else "TASK_FAILED"
        self.emit_event(event, job_id, task_name, params, parent,
                        success=job.success if event == "TASK_COMPLETED" else None)

        # Write job to JSONL
        self.write_job_jsonl(job)

        return job_id

    def run_commands(self, commands: List[str], params: Dict[str, Any],
                     timeout: Optional[float]) -> tuple:
        """Run a series of commands and return (stdout, stderr, exit_code, timed_out)."""
        workspace = self.workspace
        cwd = self.workspace

        # Clean workspace if requested
        if self.clean_cwd and os.path.exists(cwd):
            for item in os.listdir(cwd):
                item_path = os.path.join(cwd, item)
                if os.path.isfile(item_path):
                    os.remove(item_path)
                elif os.path.isdir(item_path):
                    import shutil
                    shutil.rmtree(item_path)

        full_stdout = ""
        full_stderr = ""
        exit_code = 0
        timed_out = False

        for cmd in commands:
            # Resolve parameters in command
            resolved_cmd = self.resolve_params(cmd, params)

            try:
                result = subprocess.run(
                    resolved_cmd,
                    shell=True,
                    cwd=cwd,
                    capture_output=True,
                    text=True,
                    timeout=timeout if timeout else 3600
                )

                full_stdout += result.stdout + "\n"
                full_stderr += result.stderr + "\n"
                exit_code = result.returncode

            except subprocess.TimeoutExpired:
                full_stderr += f"Command timed out after {timeout} seconds\n"
                exit_code = 124
                timed_out = True
                break

        return full_stdout, full_stderr, exit_code, timed_out

    def resolve_params(self, text: str, params: Dict[str, Any]) -> str:
        """Resolve ${params.x} and ${workspace} in text."""
        result = text

        # Resolve ${params.x}
        for key, value in params.items():
            placeholder = f"${{params.{key}}}"
            result = result.replace(placeholder, str(value))

        # Resolve ${workspace}
        result = result.replace("${workspace}", self.workspace)

        # Resolve ${output}
        if self.output_dir:
            result = result.replace("${output}", self.output_dir)

        return result

    def resolve_path(self, path: str, params: Dict[str, Any]) -> str:
        """Resolve output path."""
        path = self.resolve_params(path, params)

        # Handle ${workspace}
        if "${workspace}" in path:
            path = path.replace("${workspace}", self.workspace)
            return path

        # Relative to output dir
        if self.output_dir:
            return os.path.join(self.output_dir, path)

        return path

    def clean_output(self, text: str) -> str:
        """Clean output text."""
        # Replace curly quotes with straight quotes
        text = text.replace('\u2018', "'")  # Left single quote
        text = text.replace('\u2019', "'")  # Right single quote
        text = text.replace('\u2018', '"')   # Left double quote
        text = text.replace('\u2019', '"')   # Right double quote
        return text

    def emit_event(self, event: str, job_id: int, task: str,
                   params: Dict, parent: Optional[int], **kwargs):
        """Emit a JSON event to stdout."""
        msg = {
            "event": event,
            "job_id": job_id,
            "task": task
        }
        if parent is not None:
            msg["parent"] = parent
        print(json.dumps(msg))
        sys.stdout.flush()

    def write_job_jsonl(self, job: JobContext):
        """Write job to JSONL file."""
        jsonl_path = os.path.join(self.output_dir, "jobs.jsonl") if self.output_dir else None

        job_data = {
            "job_id": job.job_id,
            "task": job.task,
            "params": job.params,
            "stdout": job.stdout,
            "stderr": job.stderr,
            "timed_out": job.timed_out,
            "success": job.success,
            "output": job.output,
            "exit_code": job.exit_code,
            "parent": job.parent,
            "duration": job.duration
        }

        if jsonl_path:
            mode = 'a' if os.path.exists(jsonl_path) else 'w'
            with open(jsonl_path, mode) as f:
                if mode == 'a':
                    f.write('\n')
                f.write(json.dumps(job_data))

    def error(self, error_type: str, message: str) -> int:
        """Print error and return exit code."""
        print(f"{error_type}:{message}", file=sys.stderr)
        code = 2 if error_type == "SYNTAX_ERROR" else 3
        return code


# ============================================================================
# Parser and Config Loader
# ============================================================================

class Config:
    """Parsed configuration."""

    def __init__(self):
        self.entry: Optional[str] = None
        self.entry_params: Dict[str, Any] = {}
        self.clean_cwd: bool = False
        self.env: Dict[str, str] = {}

    @classmethod
    def from_toml(cls, filepath: str) -> 'Config':
        """Load configuration from TOML file."""
        if toml is None:
            raise ImportError("toml library required for config parsing")

        with open(filepath, 'r') as f:
            data = toml.load(f)

        config = cls()

        # Parse entry task
        if 'entry' in data:
            entry = str(data['entry'])
            # Parse task name and parameters
            if '(' in entry and entry.endswith(')'):
                # Has parameters: entry_task(1, x=2)
                match = re.match(r'(\w+)\((.*)\)', entry)
                if match:
                    config.entry = match.group(1)
                    args_str = match.group(2)
                    # Parse args
                    if args_str.strip():
                        parts = [p.strip() for p in args_str.split(',')]
                        for part in parts:
                            if '=' in part:
                                kw_name, kw_val = part.split('=', 1)
                                kw_val = kw_val.strip()
                                # Try to convert to number or boolean
                                if kw_val.upper() == "TRUE":
                                    config.entry_params[kw_name] = True
                                elif kw_val.upper() == "FALSE":
                                    config.entry_params[kw_name] = False
                                elif kw_val.isdigit():
                                    config.entry_params[kw_name] = int(kw_val)
                                elif '.' in kw_val and all(c.isdigit() or c == '.' for c in kw_val):
                                    config.entry_params[kw_name] = float(kw_val)
                                else:
                                    # Remove quotes
                                    config.entry_params[kw_name] = kw_val.strip('"').strip("'")
                            else:
                                config.entry_params["_args"] = config.entry_params.get("_args", [])
                                config.entry_params["_args"].append(part)
                else:
                    config.entry = entry
            else:
                config.entry = entry

        # Parse clean_cwd
        if 'clean_cwd' in data:
            config.clean_cwd = bool(data['clean_cwd'])

        # Parse env
        if 'env' in data:
            config.env = dict(data['env'])

        return config


def parse_pipeline_file(filepath: str) -> List[Task]:
    """Parse a pipeline file."""
    with open(filepath, 'r') as f:
        source = f.read()

    # Add default parameters if missing
    if "params:" in source:
        lines = source.split('\n')
        new_lines = []
        for i, line in enumerate(lines):
            if "params:" in line:
                # Check if next line is blank or ends with }
                if i + 1 < len(lines):
                    next_line = lines[i + 1].strip()
                    if next_line == '{' or (next_line and not next_line.startswith('}')):
                        # Empty params, add a placeholder
                        pass
            new_lines.append(line)
        source = '\n'.join(new_lines)

    try:
        lexer = Lexer(source)
        tokens = lexer.tokenize()
        parser = Parser(tokens)
        tasks = parser.parse_pipeline()
        return tasks
    except SyntaxError as e:
        raise ValueError(f"SYNTAX_ERROR:{str(e)}")


# ============================================================================
# Main Entry Point
# ============================================================================

def main():
    import argparse

    parser = argparse.ArgumentParser(
        description="Pipeline Executor CLI",
        formatter_class=argparse.RawDescriptionHelpFormatter
    )
    parser.add_argument(
        "pipeline",
        help="Path to pipeline file (.pipe)"
    )
    parser.add_argument(
        "--workspace",
        required=True,
        help="Working directory"
    )
    parser.add_argument(
        "--output",
        required=True,
        help="Output directory"
    )
    parser.add_argument(
        "--config",
        help="Optional TOML configuration file"
    )

    args = parser.parse_args()

    # Parse configuration
    config = Config()
    if args.config:
        if not os.path.exists(args.config):
            print(f"SYNTAX_ERROR:Config file not found: {args.config}", file=sys.stderr)
            sys.exit(2)
        try:
            config = Config.from_toml(args.config)
        except Exception as e:
            print(f"SYNTAX_ERROR:{str(e)}", file=sys.stderr)
            sys.exit(2)

    # Set environment variables from config
    for key, value in config.env.items():
        os.environ[key] = value

    # Parse pipeline file
    if not os.path.exists(args.pipeline):
        print(f"INVALID_PIPE:Pipeline file not found: {args.pipeline}", file=sys.stderr)
        sys.exit(3)

    try:
        tasks = parse_pipeline_file(args.pipeline)
    except Exception as e:
        error_msg = str(e)
        if error_msg.startswith("SYNTAX_ERROR:"):
            print(error_msg, file=sys.stderr)
            sys.exit(2)
        else:
            print(f"SYNTAX_ERROR:{error_msg}", file=sys.stderr)
            sys.exit(2)

    # Validate tasks
    task_names = set(t.name for t in tasks)
    for task in tasks:
        # Check for required fields
        if not task.run and not task.requires:
            print(f"INVALID_PIPE:Task '{task.name}' must have either 'run' or 'requires'", file=sys.stderr)
            sys.exit(3)

    # Determine entry task
    entry_task = config.entry
    entry_params = config.entry_params

    if not entry_task:
        # Look for 'main' task
        if 'main' in task_names:
            entry_task = 'main'
        else:
            print(f"INVALID_PIPE:No entry task specified and 'main' not found", file=sys.stderr)
            sys.exit(3)

    # Validate entry task exists
    if entry_task not in task_names:
        print(f"INVALID_PIPE:Entry task '{entry_task}' not found", file=sys.stderr)
        sys.exit(3)

    # Ensure output directory exists
    os.makedirs(args.output, exist_ok=True)

    # Create and run executor
    executor = TaskExecutor(
        tasks,
        args.workspace,
        args.output,
        config.__dict__,
        config.clean_cwd
    )

    try:
        exit_code = executor.run(entry_task, entry_params)
        sys.exit(exit_code)
    except Exception as e:
        print(f"INVALID_PIPE:{str(e)}", file=sys.stderr)
        sys.exit(3)


if __name__ == "__main__":
    main()

