# ============================================================================
# Interpreter
# ============================================================================

class Interpreter:
    def __init__(self, task_name: str, params: Dict[str, Any],
                 workspace: str, output: str,
                 stdout: str = "", stderr: str = ""):
        self.task_name = task_name
        self.params = params
        self.workspace = workspace
        self.output = output
        self.stdout = stdout
        self.stderr = stderr
        self.vars: Dict[str, Any] = {}
        self.task_results: Dict[str, bool] = {}

    def evaluate(self, expr: Expr) -> Any:
        if isinstance(expr, LiteralExpr):
            return expr.value

        elif isinstance(expr, VarExpr):
            if expr.name in self.vars:
                return self.vars[expr.name]
            if expr.name in self.params:
                return self.params[expr.name]
            return False

        elif isinstance(expr, BinOpExpr):
            left = self.evaluate(expr.left)
            right = self.evaluate(expr.right)

            if expr.op == '+':
                return left + right
            elif expr.op == '-':
                return left - right
            elif expr.op == '*':
                return left * right
            elif expr.op == '/':
                return left / right
            elif expr.op == '%':
                return left % right
            elif expr.op == '==':
                return left == right
            elif expr.op == '!=':
                return left != right
            elif expr.op == '<':
                return left < right
            elif expr.op == '>':
                return left > right
            elif expr.op == '<=':
                return left <= right
            elif expr.op == '>=':
                return left >= right
            elif expr.op == '&&':
                return left and right
            elif expr.op == '||':
                return left or right
            raise ValueError(f"Unknown binary op: {expr.op}")

        elif isinstance(expr, UnOpExpr):
            operand = self.evaluate(expr.operand)
            if expr.op == '!':
                return not operand
            elif expr.op == '+':
                return +operand
            elif expr.op == '-':
                return -operand
            raise ValueError(f"Unknown unary op: {expr.op}")

        elif isinstance(expr, FuncCallExpr):
            return self.call_func(expr.name, expr.args, expr.kwargs)

        elif isinstance(expr, IndexExpr):
            target = self.evaluate(expr.target)
            idx = self.evaluate(expr.index)
            return target[idx]

        elif isinstance(expr, ConcatExpr):
            left = self.evaluate(expr.left)
            right = self.evaluate(expr.right)
            return str(left) + str(right)

        raise ValueError(f"Unknown expression type: {type(expr)}")

    def call_func(self, name: str, args: List, kwargs: Dict) -> Any:
        if name == "len":
            arg = self.evaluate(args[0])
            return len(arg) if isinstance(arg, list) else 0

        if name == "contains":
            file_or_obj = self.evaluate(args[0])
            pattern = self.evaluate(args[1])
            text = ""
            if file_or_obj == "stdout":
                text = self.stdout
            elif file_or_obj == "stderr":
                text = self.stderr
            else:
                fpath = os.path.join(self.workspace, file_or_obj)
                try:
                    with open(fpath) as f:
                        text = f.read()
                except:
                    text = ""
            return pattern in text

        if name == "equals":
            file_or_obj = self.evaluate(args[0])
            expected = str(self.evaluate(args[1]))
            text = ""
            if file_or_obj == "stdout":
                text = self.stdout
            elif file_or_obj == "stderr":
                text = self.stderr
            else:
                fpath = os.path.join(self.workspace, file_or_obj)
                try:
                    with open(fpath) as f:
                        text = f.read().strip()
                except:
                    text = ""
            return text == expected

        if name == "exists":
            fpath = os.path.join(self.workspace, self.evaluate(args[0]))
            return os.path.exists(fpath)

        if name == "fail":
            task_name = args[0].name if hasattr(args[0], 'name') else None
            return not self.task_results.get(task_name, True)

        return False


class BlockInterpreter:
    def __init__(self, task_name: str, params: Dict[str, Any],
                 workspace: str, output: str,
                 stdout: str = "", stderr: str = "",
                 task_results: Dict[str, bool] = None):
        self.task_name = task_name
        self.params = params
        self.workspace = workspace
        self.output = output
        self.stdout = stdout
        self.stderr = stderr
        self.vars: Dict[str, Any] = {}
        self.task_results = task_results or {}
        self.interpreter = Interpreter(task_name, params, workspace, output, stdout, stderr)
        self.interpreter.vars = self.vars
        self.interpreter.task_results = self.task_results

    def evaluate(self, stmt: Any) -> Any:
        if isinstance(stmt, AssignStmt):
            val = self.evaluate(stmt.value)
            self.vars[stmt.name] = val
            return val

        elif isinstance(stmt, ForLoop):
            result = None
            self.evaluate(stmt.init)
            while self.interpreter.evaluate(stmt.condition):
                try:
                    for s in stmt.body:
                        r = self.evaluate(s)
                        if isinstance(r, BreakStmt):
                            break
                        elif isinstance(r, ContinueStmt):
                            continue
                        result = r
                    break
                except BreakException:
                    break
                except ContinueException:
                    pass
                self.evaluate(stmt.update)
            return result

        elif isinstance(stmt, WhileLoop):
            result = None
            while self.interpreter.evaluate(stmt.condition):
                try:
                    for s in stmt.body:
                        r = self.evaluate(s)
                        if isinstance(r, BreakStmt):
                            break
                        elif isinstance(r, ContinueStmt):
                            continue
                        result = r
                    break
                except BreakException:
                    break
                except ContinueException:
                    pass
            return result

        elif isinstance(stmt, IfStatement):
            for branch in stmt.branches:
                cond = branch.condition
                if cond is None or self.interpreter.evaluate(cond):
                    result = None
                    for s in branch.body:
                        r = self.evaluate(s)
                        if isinstance(r, ReturnStmt):
                            return r.value
                        if isinstance(r, BreakStmt):
                            break
                        elif isinstance(r, ContinueStmt):
                            continue
                        result = r
                    return result
            return None

        elif isinstance(stmt, ReturnStmt):
            return stmt

        elif isinstance(stmt, BreakStmt):
            raise BreakException()

        elif isinstance(stmt, ContinueStmt):
            raise ContinueException()

        elif isinstance(stmt, Block):
            for s in stmt.stmts:
                r = self.evaluate(s)
                if isinstance(r, ReturnStmt):
                    return r.value
            return None

        elif isinstance(stmt, Expr):
            return self.interpreter.evaluate(stmt)

        raise ValueError(f"Unknown statement type: {type(stmt)}")


class BreakException(Exception):
    pass


class ContinueException(Exception):
    pass


# ============================================================================
# Task Executor
# ============================================================================

@dataclass
class Job:
    job_id: int
    task: str
    params: Dict[str, Any]
    parent: Optional[int]
    stdout: str = ""
    stderr: str = ""
    timed_out: bool = False
    success: Dict[str, bool] = field(default_factory=dict)
    output: Optional[str] = None
    exit_code: int = 0
    duration: float = 0.0


class TaskExecutor:
    def __init__(self, program: Program, workspace: str, output: str,
                 clean_cwd: bool = False):
        self.program = program
        self.workspace = workspace
        self.output = output
        self.clean_cwd = clean_cwd
        self.jobs: List[Job] = []
        self.job_id_counter = 0
        self.task_result_map: Dict[str, bool] = {}
        self.job_jsonl_path = os.path.join(output, "jobs.jsonl")

    def run_entry(self, entry_task: str, entry_params: Dict[str, Any]) -> int:
        job_id = self._create_job(entry_task, entry_params, parent=None)
        try:
            self._execute_task(job_id)
            return 1 if self.jobs[job_id].exit_code != 0 else 0
        except ValidationError as e:
            print(f"INVALID_PIPE:{e.msg}", file=sys.stderr)
            sys.exit(3)
        except Exception as e:
            print(f"INVALID_PIPE:{e}", file=sys.stderr)
            sys.exit(3)

    def _create_job(self, task_name: str, params: Dict[str, Any],
                    parent: Optional[int] = None) -> int:
        self.job_id_counter += 1
        job = Job(
            job_id=self.job_id_counter,
            task=task_name,
            params=params.copy(),
            parent=parent
        )
        self.jobs.append(job)
        return job.job_id

    def _execute_task(self, job_id: int) -> None:
        job = self.jobs[job_id]
        task = self.program.tasks[job.task]

        # Emit TASK_STARTED
        self._emit("TASK_STARTED", job.job_id, job.task, job.params, job.parent)

        start = time.time()

        # Handle requires
        if task.requires:
            interp = BlockInterpreter(
                job.task, job.params, self.workspace,
                job.output or self.output, "", "",
                self.task_result_map
            )
            try:
                interp.evaluate(task.requires)
            except BreakException:
                pass

        # Run commands if present
        if task.run:
            cmd_texts = []
            for cmd in task.run.commands:
                resolved = self._resolve_cmd(cmd, job.params)
                cmd_texts.append(resolved)
            cmd_block = "\n".join(cmd_texts)

            # Setup workspace
            work_dir = self.workspace
            if self.clean_cwd and os.path.exists(work_dir):
                import shutil
                for item in os.listdir(work_dir):
                    p = os.path.join(work_dir, item)
                    if os.path.isfile(p):
                        os.remove(p)
                    else:
                        shutil.rmtree(p)

            try:
                result = subprocess.run(
                    cmd_block,
                    shell=True,
                    cwd=work_dir,
                    capture_output=True,
                    text=True,
                    timeout=task.timeout
                )
                job.stdout = self._clean_out(result.stdout)
                job.stderr = self._clean_out(result.stderr)
                job.exit_code = result.returncode
            except subprocess.TimeoutExpired:
                job.stdout = ""
                job.stderr = "Command timed out after {task.timeout}s\n"
                job.exit_code = 124
                job.timed_out = True

        # Evaluate success criteria
        if task.success:
            interp = BlockInterpreter(
                job.task, job.params, self.workspace,
                job.output or self.output, job.stdout, job.stderr,
                self.task_result_map
            )
            for name, expr in task.success.items():
                try:
                    job.success[name] = interp.evaluate(expr)
                except:
                    job.success[name] = False

        # Determine overall success
        exit_code = job.exit_code
        if task.success and job.success:
            if not all(job.success.values()):
                exit_code = 1

        job.exit_code = exit_code
        job.duration = time.time() - start

        # Emit final event
        event = "TASK_COMPLETED" if exit_code == 0 else "TASK_FAILED"
        self._emit(event, job.job_id, job.task, job.params, job.parent, job.success)

        self.task_result_map[job.task] = (exit_code == 0)
        self._write_job_jsonl(job)

    def _resolve_cmd(self, cmd: str, params: Dict[str, Any]) -> str:
        # ${params.x} -> value
        for k, v in params.items():
            cmd = cmd.replace(f"${{params.{k}}}", str(v))

        # ${workspace} -> workspace path
        cmd = cmd.replace("${workspace}", self.workspace)

        # ${output} -> output path
        cmd = cmd.replace("${output}", self.output or "")

        return cmd

    def _clean_out(self, text: str) -> str:
        text = text.replace('\u2018', "'").replace('\u2019', "'")
        text = text.replace('\u201c', '"').replace('\u201d', '"')
        return text

    def _emit(self, event: str, job_id: int, task: str, params: Dict, parent: Optional[int],
              success: Dict[str, bool] = None):
        msg = {"event": event, "job_id": job_id, "task": task}
        if parent is not None:
            msg["parent"] = parent
        print(json.dumps(msg))

    def _write_job_jsonl(self, job: Job):
        rec = {
            "job_id": job.job_id,
            "task": job.task,
            "params": job.params,
            "stdout": job.stdout,
            "stderr": job.stderr,
            "timed_out": job.timed_out,
            "success": job.success,
            "output": job.output,
            "exit_code": job.exit_code,
            "parent": job.parent,
            "duration": job.duration
        }
        mode = "a" if os.path.exists(self.job_jsonl_path) else "w"
        with open(self.job_jsonl_path, mode) as f:
            if mode == "a":
                f.write("\n")
            json.dump(rec, f)


# ============================================================================
# Config loader
# ============================================================================

def load_toml_config(path: str) -> Tuple[Optional[str], Dict[str, Any], bool]:
    if toml is None:
        raise ImportError("toml library required")
    data = toml.load(path)

    entry = data.get("entry", "main")
    entry_name = entry
    entry_params = {}

    if isinstance(entry, str) and "(" in entry and ")" in entry:
        m = re.match(r"(\w+)\((.*)\)", entry)
        if m:
            entry_name = m.group(1)
            args_str = m.group(2)
            if args_str.strip():
                for part in [p.strip() for p in args_str.split(",")]:
                    if "=" in part:
                        k, v = part.split("=", 1)
                        k = k.strip()
                        v = v.strip().strip('"').strip("'")
                        if v.upper() == "TRUE":
                            v = True
                        elif v.upper() == "FALSE":
                            v = False
                        elif v.isdigit():
                            v = int(v)
                        elif all(c.isdigit() or c == '.' for c in v):
                            v = float(v)
                        entry_params[k] = v

    clean_cwd = data.get("clean_cwd", False)

    # Set env vars
    if "env" in data:
        for k, v in data["env"].items():
            os.environ[k] = str(v)

    return entry_name, entry_params, clean_cwd


# ============================================================================
# Main CLI
# ============================================================================

def main():
    import argparse
    p = argparse.ArgumentParser()
    p.add_argument("pipeline")
    p.add_argument("--workspace", required=True)
    p.add_argument("--output", required=True)
    p.add_argument("--config")
    args = p.parse_args()

    # Parse pipeline
    if not os.path.exists(args.pipeline):
        print(f"INVALID_PIPE:File not found: {args.pipeline}", file=sys.stderr)
        sys.exit(3)

    with open(args.pipeline) as f:
        source = f.read()

    try:
        lexer = Lexer(source)
        tokens = lexer.tokens()
        parser = Parser(tokens)
        program = parser.parse_program()
    except ParseError as e:
        print(f"SYNTAX_ERROR:{e.msg}", file=sys.stderr)
        sys.exit(2)

    # Config
    entry_name = "main"
    entry_params = {}
    clean_cwd = False

    if args.config:
        if not os.path.exists(args.config):
            print(f"SYNTAX_ERROR:Config not found: {args.config}", file=sys.stderr)
            sys.exit(2)
        try:
            entry_name, entry_params, clean_cwd = load_toml_config(args.config)
        except Exception as e:
            print(f"SYNTAX_ERROR:{e}", file=sys.stderr)
            sys.exit(2)

    # Validate entry task
    if entry_name not in program.tasks:
        print(f"INVALID_PIPE:Task '{entry_name}' not found", file=sys.stderr)
        sys.exit(3)

    # Ensure output dir exists
    os.makedirs(args.output, exist_ok=True)

    # Run
    executor = TaskExecutor(program, args.workspace, args.output, clean_cwd)
    exit_code = executor.run_entry(entry_name, entry_params)
    sys.exit(exit_code)


if __name__ == "__main__":
    main()
ENDOFCODE

