# ============================================================================
# Interpreter
# ============================================================================

class Interpreter:
    def __init__(self, task_name: str, params: Dict,
                 workspace: str, output: str,
                 stdout: str = "", stderr: str = "",
                 results: Dict[str, bool] = None):
        self.task_name = task_name
        self.params = params
        self.workspace = workspace
        self.output = output
        self.stdout = stdout
        self.stderr = stderr
        self.vars: Dict[str, Any] = {}
        self.results = results or {}

    def evaluate(self, expr: Expr) -> Any:
        if isinstance(expr, Literal): return expr.value
        if isinstance(expr, Var):
            if expr.name in self.vars: return self.vars[expr.name]
            if expr.name in self.params: return self.params[expr.name]
            return False
        if isinstance(expr, BinOp):
            l = self.evaluate(expr.left)
            r = self.evaluate(expr.right)
            if expr.op == '+': return l + r
            if expr.op == '-': return l - r
            if expr.op == '*': return l * r
            if expr.op == '/': return l / r
            if expr.op == '%': return l % r
            if expr.op == '==': return l == r
            if expr.op != '=': return l != r
            if expr.op == '<': return l < r
            if expr.op == '>': return l > r
            if expr.op == '<=': return l <= r
            if expr.op == '>=': return l >= r
            if expr.op == '&&': return l and r
            if expr.op == '||': return l or r
            raise ValueError(expr.op)
        if isinstance(expr, UnOp):
            val = self.evaluate(expr.operand)
            if expr.op == '!': return not val
            if expr.op == '+': return +val
            if expr.op == '-': return -val
            raise ValueError(expr.op)
        if isinstance(expr, CallExpr):
            return self.call_func(expr)
        if isinstance(expr, IndexExpr):
            tgt = self.evaluate(expr.target)
            return tgt[self.evaluate(expr.idx)]
        if isinstance(expr, ConcatExpr):
            return str(self.evaluate(expr.left)) + str(self.evaluate(expr.right))
        raise ValueError(str(type(expr)))

    def call_func(self, call: CallExpr) -> Any:
        n = call.name
        if n == "len":
            return len(self.evaluate(call.args[0]))
        if n == "contains":
            src = self.evaluate(call.args[0])
            pat = self.evaluate(call.args[1])
            txt = ""
            if src == "stdout": txt = self.stdout
            elif src == "stderr": txt = self.stderr
            else:
                fp = os.path.join(self.workspace, src)
                try: txt = open(fp).read()
                except: pass
            return pat in txt
        if n == "equals":
            src = self.evaluate(call.args[0])
            exp = str(self.evaluate(call.args[1]))
            txt = ""
            if src == "stdout": txt = self.stdout.strip()
            elif src == "stderr": txt = self.stderr.strip()
            else:
                fp = os.path.join(self.workspace, src)
                try: txt = open(fp).read().strip()
                except: pass
            return txt == exp
        if n == "exists":
            fp = os.path.join(self.workspace, self.evaluate(call.args[0]))
            return os.path.exists(fp)
        if n == "fail":
            return not self.results.get(call.args[0].name, True)
        return False

    def eval_stmt(self, stmt: Statement) -> Any:
        if isinstance(stmt, AssignStmt):
            self.vars[stmt.name] = self.evaluate(stmt.value)
            return self.vars[stmt.name]
        if isinstance(stmt, ForStmt):
            result = None
            self.eval_stmt(stmt.init) if stmt.init else None
            while self.evaluate(stmt.cond):
                try:
                    for s in stmt.body.stmts: result = self.eval_stmt(s)
                    if stmt.update:
                        self.eval_stmt(AssignStmt(
                            stmt.update.left.name,
                            BinOp(Var(stmt.update.left.name), '+', Literal(1))
                        ) if isinstance(stmt.update, Expr) else self.eval_stmt(stmt.update))
                except BreakException: break
                except ContinueException: pass
                if stmt.update and not isinstance(stmt.update, Expr):
                    pass  # already eval'd
            return result
        if isinstance(stmt, WhileStmt):
            result = None
            while self.evaluate(stmt.cond):
                try:
                    for s in stmt.body.stmts: result = self.eval_stmt(s)
                except BreakException: break
                except ContinueException: pass
            return result
        if isinstance(stmt, IfStmt):
            for c in stmt.clauses:
                if c.cond is None or self.evaluate(c.cond):
                    result = None
                    for s in c.body.stmts: result = self.eval_stmt(s)
                    return result
            return None
        if isinstance(stmt, ReturnStmt):
            return BreakException() if stmt.expr is None else self.evaluate(stmt.expr)
        if isinstance(stmt, BreakStmt): raise BreakException()
        if isinstance(stmt, ContinueStmt): raise ContinueException()
        if isinstance(stmt, ExprStmt): return self.evaluate(stmt.expr)
        if isinstance(stmt, Block):
            result = None
            for s in stmt.stmts: result = self.eval_stmt(s)
            return result
        raise ValueError(str(type(stmt)))

class BreakException(Exception): pass
class ContinueException(Exception): pass


# ============================================================================
# Executor
# ============================================================================

@dataclass
class Job:
    job_id: int; task: str; params: Dict[str, Any]
    parent: Optional[int] = None
    stdout: str = ""; stderr: str = ""
    timed_out: bool = False
    success: Dict[str, bool] = field(default_factory=dict)
    output: Optional[str] = None
    exit_code: int = 0; duration: float = 0.0


class Executor:
    def __init__(self, program: Program, workspace: str, output: str,
                 clean_cwd: bool = False):
        self.program = program
        self.workspace = workspace
        self.output = output
        self.clean_cwd = clean_cwd
        self.jobs: List[Job] = []
        self.job_counter = 0
        self.results: Dict[str, bool] = {}
        self.jsonl_path = os.path.join(output, "jobs.jsonl")

    def run(self, entry: str, params: Dict) -> int:
        jid = self._new_job(entry, params, None)
        try:
            self._exec(jid)
            return 1 if self.jobs[jid].exit_code != 0 else 0
        except ValidationError as e:
            print(f"INVALID_PIPE:{e.msg}", file=sys.stderr)
            sys.exit(3)
        except Exception as e:
            print(f"INVALID_PIPE:{e}", file=sys.stderr)
            sys.exit(3)

    def _new_job(self, task: str, params: Dict, parent: Optional[int]) -> int:
        self.job_counter += 1
        self.jobs.append(Job(self.job_counter, task, params, parent))
        return self.job_counter

    def _exec(self, jid: int):
        job = self.jobs[jid]
        task = self.program.tasks[job.task]
        self._emit("TASK_STARTED", job.job_id, job.task, job.params, job.parent)
        start = time.time()

        # Run requires block
        if task.requires:
            interp = self._make_interp(job)
            try:
                interp.eval_stmt(task.requires)
            except BreakException: pass

        # Run commands if present
        if task.run:
            work_dir = self.workspace
            if self.clean_cwd and os.path.exists(work_dir):
                import shutil
                for item in os.listdir(work_dir):
                    p = os.path.join(work_dir, item)
                    if os.path.isfile(p): os.remove(p)
                    else: shutil.rmtree(p)

            cmds = []
            for cmd in task.run.cmds:
                cmds.append(self._resolve(cmd, job.params))
            full_cmd = "\n".join(cmds)

            try:
                r = subprocess.run(full_cmd, shell=True, cwd=work_dir,
                                   capture_output=True, text=True,
                                   timeout=task.timeout)
                job.stdout = self._clean(r.stdout)
                job.stderr = self._clean(r.stderr)
                job.exit_code = r.returncode
            except subprocess.TimeoutExpired:
                job.stdout = ""
                job.stderr = f"Command timed out after {task.timeout}s\n"
                job.exit_code = 124
                job.timed_out = True

        # Evaluate success conditions
        if task.success:
            interp = self._make_interp(job)
            for name, expr in task.success.items():
                try:
                    job.success[name] = interp.evaluate(expr)
                except:
                    job.success[name] = False

        job.exit_code = job.exit_code
        if task.success and job.success:
            if not all(job.success.values()): job.exit_code = 1

        job.duration = time.time() - start
        self.results[job.task] = (job.exit_code == 0)
        self._write_jsonl(job)
        self._emit("TASK_COMPLETED" if job.exit_code == 0 else "TASK_FAILED",
                   job.job_id, job.task, job.params, job.parent, job.success)

    def _make_interp(self, job: Job) -> Interpreter:
        out = job.output or self.output
        return Interpreter(job.task, job.params, self.workspace, out,
                           job.stdout, job.stderr, self.results)

    def _resolve(self, cmd: str, params: Dict) -> str:
        for k, v in params.items():
            cmd = cmd.replace(f"${{params.{k}}}", str(v))
        cmd = cmd.replace("${workspace}", self.workspace)
        return cmd.replace("${output}", self.output or "")

    def _clean(self, text: str) -> str:
        return text.replace('\u2018', "'").replace('\u2019', "'")
                   .replace('\u201c', '"').replace('\u201d', '"')

    def _emit(self, evt: str, jid: int, task: str, params: Dict,
              parent: Optional[int], success: Dict = None):
        msg = {"event": evt, "job_id": jid, "task": task}
        if parent is not None: msg["parent"] = parent
        print(json.dumps(msg))

    def _write_jsonl(self, job: Job):
        rec = {
            "job_id": job.job_id, "task": job.task, "params": job.params,
            "stdout": job.stdout, "stderr": job.stderr,
            "timed_out": job.timed_out, "success": job.success,
            "output": job.output, "exit_code": job.exit_code,
            "parent": job.parent, "duration": job.duration
        }
        mode = "a" if os.path.exists(self.jsonl_path) else "w"
        with open(self.jsonl_path, mode) as f:
            if mode == "a": f.write("\n")
            json.dump(rec, f)


# ============================================================================
# Config loading
# ============================================================================

def load_config(path: str):
    if toml is None:
        raise ImportError("toml required for config")
    data = toml.load(path)

    entry = data.get("entry", "main")
    entry_name = entry if isinstance(entry, str) else str(entry)
    entry_params = {}

    if isinstance(entry, str) and "(" in entry and ")" in entry:
        m = re.match(r"(\w+)\((.*)\)", entry)
        if m:
            entry_name = m.group(1)
            for part in [p.strip() for p in m.group(2).split(",") if p.strip()]:
                if "=" in part:
                    k, v = part.split("=", 1)
                    k = k.strip()
                    v = v.strip().strip('"').strip("'")
                    if v.upper() == "TRUE": v = True
                    elif v.upper() == "FALSE": v = False
                    elif v.isdigit(): v = int(v)
                    elif all(c.isdigit() or c == '.' for c in v): v = float(v)
                    entry_params[k] = v

    clean_cwd = data.get("clean_cwd", False)

    if "env" in data:
        for k, v in data["env"].items():
            os.environ[k] = str(v)

    return entry_name, entry_params, clean_cwd


# ============================================================================
# CLI
# ============================================================================

def main():
    import argparse
    ap = argparse.ArgumentParser()
    ap.add_argument("pipeline")
    ap.add_argument("--workspace", required=True)
    ap.add_argument("--output", required=True)
    ap.add_argument("--config")
    args = ap.parse_args()

    if not os.path.exists(args.pipeline):
        print(f"INVALID_PIPE:File '{args.pipeline}' not found", file=sys.stderr)
        sys.exit(3)

    with open(args.pipeline) as f:
        src = f.read()

    try:
        lex = Lexer(src)
        toks = lex.tokens()
        pars = Parser(toks)
        prog = pars.parse()
    except ParseError as e:
        print(f"SYNTAX_ERROR:{e.msg}", file=sys.stderr)
        sys.exit(2)

    entry_name = "main"
    entry_params = {}
    clean_cwd = False

    if args.config:
        if not os.path.exists(args.config):
            print(f"SYNTAX_ERROR:Config '{args.config}' not found", file=sys.stderr)
            sys.exit(2)
        try:
            entry_name, entry_params, clean_cwd = load_config(args.config)
        except Exception as e:
            print(f"SYNTAX_ERROR:{e}", file=sys.stderr)
            sys.exit(2)

    if entry_name not in prog.tasks:
        print(f"INVALID_PIPE:Task '{entry_name}' not defined", file=sys.stderr)
        sys.exit(3)

    os.makedirs(args.output, exist_ok=True)

    ex = Executor(prog, args.workspace, args.output, clean_cwd)
    exit(ex.run(entry_name, entry_params))


if __name__ == "__main__":
    main()
ENDFILE

