    def peek(self, o=0):
        p = self.pos + o; return self.src[p] if p < len(self.src) else '\0'
    def advance(self) -> str:
        ch = self.peek(); 
        if ch == '\\n': self.line += 1; self.col = 1
        else: self.col += 1
        self.pos += 1; return ch
    def skip_ws(self):
        while self.peek() in ' \\t\\r': self.advance()
    def tokens(self) -> List[Token]:
        res = []
        while self.pos < len(self.src):
            ch = self.peek()
            if ch in ' \\t\\r': self.skip_ws(); continue
            if ch == '\\n': res.append(Token(TokenType.NEWLINE, '\\n', self.line, self.col)); self.advance(); continue
            if ch == '/' and self.peek(1) == '/':
                while self.peek() not in '\\n\\0': self.advance()
                continue
            if ch == '\"':
                start = self.pos; q = self.advance()
                while self.peek() not in ('\\0', q):
                    if self.peek() == '\\\\': self.advance()
                    self.advance()
                if self.peek() == q: self.advance()
                res.append(Token(TokenType.STRING, self.src[start:self.pos], self.line, self.col))
                continue
