# Interpreter
class Interpreter:
    def __init__(self, task_name, params, workspace, output, stdout="", stderr="", results=None):
        self.task_name = task_name; self.params = params
        self.workspace = workspace; self.output = output
        self.stdout = stdout; self.stderr = stderr
        self.vars: Dict[str, Any] = {}
        self.results = results or {}

    def evaluate(self, expr):
        if isinstance(expr, Literal): return expr.value
        if isinstance(expr, Var): 
            if expr.name in self.vars: return self.vars[expr.name]
            if expr.name in self.params: return self.params[expr.name]
            return False
        if isinstance(expr, BinOp):
            l = self.evaluate(expr.left); r = self.evaluate(expr.right)
            if expr.op == '+': return l + r
            if expr.op == '-': return l - r
            if expr.op == '*': return l * r
            if expr.op == '/': return l / r
            if expr.op == '%': return l % r
            if expr.op == '==': return l == r
            if expr.op != '=': return l != r
            if expr.op == '<': return l < r
            if expr.op == '>': return l > r
            if expr.op == '<=': return l <= r
            if expr.op == '>=': return l >= r
            if expr.op == '&&': return l and r
            if expr.op == '||': return l or r
            raise ValueError(expr.op)
        if isinstance(expr, UnOp):
            v = self.evaluate(expr.operand)
            if expr.op == '!': return not v
            if expr.op == '+': return +v
            if expr.op == '-': return -v
            raise ValueError(expr.op)
        if isinstance(expr, CallExpr): return self.call_func(expr)
        if isinstance(expr, IndexExpr): return self.evaluate(expr.target)[self.evaluate(expr.idx)]
        raise ValueError(str(type(expr)))

    def call_func(self, c):
        n = c.name
        if n == 'len': return len(self.evaluate(c.args[0]))
        if n == 'contains':
            src = self.evaluate(c.args[0]); pat = self.evaluate(c.args[1])
            txt = self.stdout if src == 'stdout' else self.stderr if src == 'stderr' else self._read_file(src)
            return pat in txt
        if n == 'equals':
            src = self.evaluate(c.args[0]); exp = str(self.evaluate(c.args[1]))
            txt = self.stdout.strip() if src == 'stdout' else self.stderr.strip() if src == 'stderr' else self._read_file(src).strip()
            return txt == exp
        if n == 'exists': return os.path.exists(os.path.join(self.workspace, self.evaluate(c.args[0])))
        if n == 'fail': return not self.results.get(c.args[0].name, True)
        return False

    def _read_file(self, src):
        fp = os.path.join(self.workspace, src)
        try: return open(fp).read()
        except: return ""

    def eval_stmt(self, stmt):
        if isinstance(stmt, AssignStmt):
            self.vars[stmt.name] = self.evaluate(stmt.value)
            return self.vars[stmt.name]
        if isinstance(stmt, ForStmt):
            result = None; self.eval_stmt(stmt.init) if stmt.init else None
            while self.evaluate(stmt.cond):
                try:
                    for s in stmt.body.stmts: result = self.eval_stmt(s)
                    if stmt.update: self.eval_stmt(stmt.update)
                except BreakException: break
                except ContinueException: pass
            return result
        if isinstance(stmt, WhileStmt):
            result = None
            while self.evaluate(stmt.cond):
                try:
                    for s in stmt.body.stmts: result = self.eval_stmt(s)
                except BreakException: break
                except ContinueException: pass
            return result
        if isinstance(stmt, IfStmt):
            for c in stmt.clauses:
                if c.cond is None or self.evaluate(c.cond):
                    result = None
                    for s in c.body.stmts: result = self.eval_stmt(s)
                    return result
            return None
        if isinstance(stmt, ReturnStmt):
            return BreakException() if stmt.expr is None else self.evaluate(stmt.expr)
        if isinstance(stmt, Block):
            result = None
            for s in stmt.stmts: result = self.eval_stmt(s)
            return result
        if isinstance(stmt, BreakStmt): raise BreakException()
        if isinstance(stmt, ContinueStmt): raise ContinueException()
        if isinstance(stmt, ExprStmt): return self.evaluate(stmt.expr)
        raise ValueError(str(type(stmt)))

class BreakException(Exception): pass
class ContinueException(Exception): pass

# Executor
@dataclass
class Job:
    job_id: int; task: str; params: Dict[str, Any]; parent: Optional[int] = None
    stdout: str = ""; stderr: str = ""; timed_out: bool = False
    success: Dict[str, bool] = field(default_factory=dict)
    output: Optional[str] = None; exit_code: int = 0; duration: float = 0.0

class Executor:
    def __init__(self, prog, ws, out, clean_cwd=False):
        self.prog = prog; self.ws = ws; self.out = out; self.clean_cwd = clean_cwd
        self.jobs: List[Job] = []; self.jc = 0; self.results: Dict[str, bool] = {}
        self.jsonl = os.path.join(out, "jobs.jsonl")

    def run(self, entry, params):
        jid = self._new_job(entry, params, None)
        try:
            self._exec(jid)
            return 1 if self.jobs[jid].exit_code != 0 else 0
        except ValidationError as e:
            print(f"INVALID_PIPE:{e.msg}", file=sys.stderr)
            sys.exit(3)
        except Exception as e:
            print(f"INVALID_PIPE:{e}", file=sys.stderr); sys.exit(3)

    def _new_job(self, task, params, parent):
        self.jc += 1
        self.jobs.append(Job(self.jc, task, params, parent)); return self.jc

    def _exec(self, jid):
        job = self.jobs[jid]; task = self.prog.tasks[job.task]
        self._emit("TASK_STARTED", job.job_id, job.task, job.params, job.parent)
        s = time.time()

        if task.requires:
            interp = self._make_interp(job)
            try: interp.eval_stmt(task.requires)
            except BreakException: pass

        if task.run:
            wd = self.ws
            if self.clean_cwd and os.path.exists(wd):
                import shutil
                for item in os.listdir(wd):
                    p = os.path.join(wd, item)
                    if os.path.isfile(p): os.remove(p)
                    else: shutil.rmtree(p)
            cmds = [self._resolve(c, job.params) for c in task.run.cmds]
            cmd = "\\n".join(cmds)
            try:
                r = subprocess.run(cmd, shell=True, cwd=wd, capture_output=True, text=True, timeout=task.timeout)
                job.stdout = self._clean(r.stdout); job.stderr = self._clean(r.stderr); job.exit_code = r.returncode
            except subprocess.TimeoutExpired:
                job.stdout = ""; job.stderr = f"Timeout after {task.timeout}s\\n"; job.exit_code = 124; job.timed_out = True

        if task.success:
            interp = self._make_interp(job)
            for name, expr in task.success.items():
                try: job.success[name] = interp.evaluate(expr)
                except: job.success[name] = False

        if task.success and job.success and not all(job.success.values()): job.exit_code = 1
        job.duration = time.time() - s
        self.results[job.task] = (job.exit_code == 0)
        self._write_jsonl(job)
        self._emit("TASK_COMPLETED" if job.exit_code == 0 else "TASK_FAILED",
                    job.job_id, job.task, job.params, job.parent, job.success)

    def _make_interp(self, job):
        out = job.output or self.out
        return Interpreter(job.task, job.params, self.ws, out, job.stdout, job.stderr, self.results)

    def _resolve(self, cmd, params):
        for k, v in params.items(): cmd = cmd.replace(f"$${{params.{k}}}}", str(v))
        cmd = cmd.replace("$${workspace}}", self.ws)
        return cmd.replace("$${output}}", self.out or "")

    def _clean(self, t):
        return t.replace(chr(8216), "'").replace(chr(8217), "'").replace(chr(8220), '"').replace(chr(8221), '"')

    def _emit(self, evt, jid, task, params, parent, success=None):
        msg = {"event": evt, "job_id": jid, "task": task}
        if parent is not None: msg["parent"] = parent
        print(json.dumps(msg))

    def _write_jsonl(self, job):
        rec = {
            "job_id": job.job_id, "task": job.task, "params": job.params,
            "stdout": job.stdout, "stderr": job.stderr, "timed_out": job.timed_out,
            "success": job.success, "output": job.output, "exit_code": job.exit_code,
            "parent": job.parent, "duration": job.duration
        }
        mode = "a" if os.path.exists(self.jsonl) else "w"
        with open(self.jsonl, mode) as f:
            if mode == "a": f.write("\\n")
            json.dump(rec, f)

# Config
def load_config(path):
    if toml is None: raise ImportError("toml needed for config")
    data = toml.load(path)
    entry = data.get("entry", "main")
    entry_name = entry if isinstance(entry, str) else str(entry)
    entry_params = {}
    if isinstance(entry, str) and "(" in entry and ")" in entry:
        m = re.match(r"(\\w+)\\((.+)\\)", entry)
        if m:
            entry_name = m.group(1)
            for part in [p.strip() for p in m.group(2).split(",") if p.strip()]:
                if "=" in part:
                    k, v = part.split("=", 1)
                    k = k.strip(); v = v.strip().strip('"').strip("'")
                    if v.upper() == "TRUE": v = True
                    elif v.upper() == "FALSE": v = False
                    elif v.isdigit(): v = int(v)
                    elif all(c.isdigit() or c == '.' for c in v): v = float(v)
                    entry_params[k] = v
    clean_cwd = data.get("clean_cwd", False)
    if "env" in data:
        for k, v in data["env"].items(): os.environ[k] = str(v)
    return entry_name, entry_params, clean_cwd

# CLI
def main():
    import argparse; ap = argparse.ArgumentParser()
    ap.add_argument("pipeline"); ap.add_argument("--workspace", required=True)
    ap.add_argument("--output", required=True); ap.add_argument("--config")
    args = ap.parse_args()
    if not os.path.exists(args.pipeline):
        print(f"INVALID_PIPE:File '{args.pipeline}' not found", file=sys.stderr); sys.exit(3)
