    if args.config:
        if not os.path.exists(args.config):
            print(f"SYNTAX_ERROR:Config '{args.config}' not found", file=sys.stderr); sys.exit(2)
        try:
            entry_name, entry_params, clean_cwd = load_config(args.config)
        except Exception as e:
            print(f"SYNTAX_ERROR:{e}", file=sys.stderr); sys.exit(2)
    if entry_name not in prog.tasks:
        print(f"INVALID_PIPE:Task '{entry_name}' not defined", file=sys.stderr); sys.exit(3)
    os.makedirs(args.output, exist_ok=True)
    ex = Executor(prog, args.workspace, args.output, clean_cwd)
    sys.exit(ex.run(entry_name, entry_params))

if __name__ == "__main__": main()
