    '&&': TokenType.AND, '||': TokenType.OR, '!': TokenType.NOT,
    '=': TokenType.ASSIGN, '+': TokenType.PLUS, '-': TokenType.MINUS,
    '*': TokenType.MULT, '/': TokenType.DIV, '%': TokenType.MOD,
    '(': TokenType.LPAREN, ')': TokenType.RPAREN,
    '{': TokenType.LBRACE, '}': TokenType.RBRACE,
    '['': TokenType.LBRACK, ']': TokenType.RBRACK,
    ':': TokenType.COLON, ';': TokenType.SEMI, ',': TokenType.COMMA, '.': TokenType.DOT
}

class Token:
    __slots__ = ('type', 'value', 'line', 'col')
    def __init__(self, type, value, line, col):
        self.type = type; self.value = value; self.line = line; self.col = col
    def __repr__(self): return f"{self.type.name}({repr(self.value)})"

class Lexer:
    def __init__(self, s):
        self.src = s; self.pos = 0; self.line = 1; self.col = 1
    def peek(self, o=0): p = self.pos+o; return self.src[p] if p < len(self.src) else ''
    def advance(self):
        ch = self.peek()
        if ch == '\\n': self.line += 1; self.col = 1
        else: self.col += 1
        self.pos += 1; return ch
    def tokens(self):
        res = []; 
        while self.pos < len(self.src):
            ch = self.peek()
            if ch in ' \\t\\r': 
                while self.peek() in ' \\t\\r': self.advance()
                continue
            if ch == '\\n':
                res.append(Token(TokenType.NEWLINE, '\\n', self.line, self.col)); self.advance(); continue
            if ch == '/' and self.peek(1) == '/':
                while self.peek() not in '\\n': self.advance()
                continue
            if ch == '\"':
                start = self.pos; q = self.advance()
                while self.peek() not in ('', q):
                    if self.peek() == '\\\\': self.advance()
                    self.advance()
                if self.peek() == q: self.advance()
                res.append(Token(TokenType.STRING, self.src[start:self.pos], self.line, self.col)); continue
            if ch.isdigit() or (ch == '.' and self.peek(1).isdigit()):
                start = self.pos
                while self.peek().isdigit() or self.peek() == '.': self.advance()
                res.append(Token(TokenType.NUMBER, self.src[start:self.pos], self.line, self.col)); continue
            if ch.isalpha() or ch == '_':
                start = self.pos
                while self.peek().isalnum() or self.peek() == '_': self.advance()
                val = self.src[start:self.pos]; vl = val.lower()
                if vl in KEYWORDS: res.append(Token(KEYWORDS[vl], val, self.line, self.col))
                elif val in ('TRUE', 'FALSE'): res.append(Token(TokenType.BOOL, val, self.line, self.col))
                else: res.append(Token(TokenType.IDENTIFIER, val, self.line, self.col))
                continue
            for op, ttype in OP_SYMS.items():
                if self.src.startswith(op, self.pos):
                    res.append(Token(ttype, op, self.line, self.col))
                    self.pos += len(op); self.col += len(op); break
            else: raise ParseError(f"Unknown '{ch}' at {self.line}:{self.col}")
        res.append(Token(TokenType.EOF, '', self.line, self.col))
        return res

# ---- AST ----
class ASTNode: pass

@dataclass class ParamDef(ASTNode):
    name: str; type_str: str; default: Any = None

@dataclass class RunBlock(ASTNode):
    cmds: List[str]

@dataclass class TaskDef(ASTNode):
    name: str; params: List['ParamDef']; run: RunBlock = None
    success: Dict[str, 'Expr'] = None; requires: 'Expr' = None
    output: str = None; timeout: float = None

@dataclass class Program(ASTNode):
    tasks: Dict[str, TaskDef]

@dataclass class Expr(ASTNode): pass
@dataclass class Literal(Expr): value: Any
@dataclass class Var(Expr): name: str
@dataclass class BinOp(Expr): left: 'Expr'; op: str; right: 'Expr'
@dataclass class UnOp(Expr): operand: 'Expr'; op: str
@dataclass class CallExpr(Expr): name: str; args: List['Expr']; kwargs: Dict[str, 'Expr']
@dataclass class IndexExpr(Expr): target: 'Expr'; idx: 'Expr'

@dataclass class Statement(ASTNode): pass
@dataclass class Block(Statement): stmts: List[Statement]
@dataclass class AssignStmt(Statement): name: str; value: 'Expr'
@dataclass class ForStmt(Statement): init: AssignStmt; cond: 'Expr'; update: 'Expr'; body: Block
@dataclass class WhileStmt(Statement): cond: 'Expr'; body: Block
@dataclass class IfClause: cond: 'Expr'; body: Block
@dataclass class IfStmt(Statement): clauses: List[IfClause]
@dataclass class ReturnStmt(Statement): expr: 'Expr' = None
@dataclass class BreakStmt(Statement): pass
@dataclass class ContinueStmt(Statement): pass
@dataclass class ExprStmt(Statement): expr: 'Expr'

# ---- Parser ----
class Parser:
    def __init__(self, toks): self.toks = toks; self.pos = 0
    def peek(self, o=0): 
        p = self.pos+o; return self.toks[p] if p < len(self.toks) else self.toks[-1]
    def advance(self): tok = self.peek(); self.pos += 1; return tok
    def expect(self, ttype, val=None):
        tok = self.advance()
        if tok.type != ttype: raise ParseError(f"Expected {ttype.name}, got {tok.type.name}")
        if val and tok.value != val: raise ParseError(f"Expected '{val}', got '{tok.value}'")
        return tok

    def parse(self):
        tasks = {}
        while self.peek().type != TokenType.EOF:
            if self.peek().type == TokenType.TASK: 
                t = self.parse_task(); tasks[t.name] = t
            else: raise ParseError(f"Unexpected {self.peek()}")
        return Program(tasks)

    def parse_task(self):
        self.expect(TokenType.TASK); name = self.expect(TokenType.IDENTIFIER).value
        params = []; run = None; success = {}; requires = None; output = None; timeout = None
        if self.peek().type == TokenType.PARAMS:
            self.expect(TokenType.PARAMS); self.expect(TokenType.LBRACE)
            params = self.parse_params(); self.expect(TokenType.RBRACE)
        if self.peek().type == TokenType.RUN: run = self.parse_run()
        if self.peek().type == TokenType.SUCCESS:
            self.expect(TokenType.SUCCESS); self.expect(TokenType.LBRACE)
            while self.peek().type == TokenType.IDENTIFIER:
                sname = self.advance().value; self.expect(TokenType.LBRACE)
                expr = self.parse_expr_or_stmt(); self.expect(TokenType.RBRACE)
                success[sname] = expr
            self.expect(TokenType.RBRACE)
        if self.peek().type == TokenType.REQUIRES:
            self.expect(TokenType.REQUIRES); requires = self.parse_stmt()
        if self.peek().type == TokenType.OUTPUT:
            self.expect(TokenType.OUTPUT); output = self.expect(TokenType.STRING).value.strip('"')
        if self.peek().type == TokenType.TIMEOUT:
            self.expect(TokenType.TIMEOUT); timeout = float(self.expect(TokenType.NUMBER).value)
        return TaskDef(name, params, run, success, requires, output, timeout)

    def parse_params(self):
        params = []
        while self.peek().type == TokenType.IDENTIFIER:
            name = self.advance().value; self.expect(TokenType.COLON)
            type_str = self.expect(TokenType.IDENTIFIER).value; default = None
            if self.peek().type == TokenType.ASSIGN: self.advance(); default = self.parse_literal()
            if self.peek().type == TokenType.SEMI: self.advance()
            params.append(ParamDef(name, type_str, default))
        return params

    def parse_literal(self):
        t = self.peek()
        if t.type == TokenType.BOOL: self.advance(); return True if t.value == 'TRUE' else False
        if t.type == TokenType.NUMBER: self.advance(); val = t.value
        return float(val) if '.' in val else int(val)
        if t.type == TokenType.STRING: self.advance(); return t.value.strip('"')
        raise ParseError(f"Expected literal, got {t}")

    def parse_run(self):
        self.expect(TokenType.RUN); self.expect(TokenType.LBRACE); cmds = []
        d = 0; start = self.pos
        while True:
            tok = self.peek()
            if tok.type == TokenType.LBRACE: d += 1
            elif tok.type == TokenType.RBRACE:
                if d == 0: break
                d -= 1
            self.pos += 1
        cmd = ''.join(t.value for t in self.toks[start:self.pos]).strip()
        if cmd and cmd != '}': cmds.append(cmd)
        self.expect(TokenType.RBRACE); return RunBlock(cmds)

    def parse_expr_or_stmt(self):
        if self.peek().type == TokenType.LBRACE:
            self.advance(); stmts = self.parse_stmt_block(); self.expect(TokenType.RBRACE)
            return Block(stmts)
        return self.parse_expr()

    def parse_stmt_block(self):
        stmts = []
        while self.peek().type not in (TokenType.RBRACE, TokenType.EOF):
            stmts.append(self.parse_stmt())
        return stmts

    def parse_stmt(self):
        t = self.peek()
        if t.type == TokenType.FOR: return self.parse_for()
        if t.type == TokenType.WHILE: return self.parse_while()
        if t.type in (TokenType.IF, TokenType.ELIF, TokenType.ELSE): return self.parse_if()
        if t.type == TokenType.RETURN: return self.parse_return()
        if t.type == TokenType.BREAK: self.advance(); return BreakStmt()
        if t.type == TokenType.CONTINUE: self.advance(); return ContinueStmt()
        if self.peek(1).type == TokenType.ASSIGN: return self.parse_assign()
        return ExprStmt(self.parse_expr())

    def parse_assign(self):
        name = self.expect(TokenType.IDENTIFIER).value; self.expect(TokenType.ASSIGN)
        value = self.parse_expr(); 
        if self.peek().type == TokenType.SEMI: self.advance()
        return AssignStmt(name, value)

    def parse_for(self):
        self.expect(TokenType.FOR); self.expect(TokenType.LPAREN)
        init = None if self.peek().type == TokenType.SEMI else self.parse_assign()
        self.expect(TokenType.SEMI); cond = self.parse_expr(); self.expect(TokenType.SEMI)
        update = None if self.peek().type == TokenType.RPAREN else self.parse_expr()
        self.expect(TokenType.RPAREN); self.expect(TokenType.LBRACE)
        body = Block(self.parse_stmt_block()); self.expect(TokenType.RBRACE)
        return ForStmt(init, cond, update, body)

    def parse_while(self):
        self.expect(TokenType.WHILE); self.expect(TokenType.LPAREN)
        cond = self.parse_expr(); self.expect(TokenType.RPAREN); self.expect(TokenType.LBRACE)
        body = Block(self.parse_stmt_block()); self.expect(TokenType.RBRACE)
        return WhileStmt(cond, body)

    def parse_if(self):
        clauses = []
        while self.peek().type in (TokenType.IF, TokenType.ELIF, TokenType.ELSE):
            has_cond = self.peek().type != TokenType.ELSE
            if has_cond:
                self.advance(); self.expect(TokenType.LPAREN); cond = self.parse_expr(); self.expect(TokenType.RPAREN)
            else: self.advance(); cond = None
            self.expect(TokenType.LBRACE); body = Block(self.parse_stmt_block()); self.expect(TokenType.RBRACE)
            clauses.append(IfClause(cond, body))
            if self.peek().type not in (TokenType.ELIF, TokenType.ELSE): break
        return IfStmt(clauses)

    def parse_return(self):
        self.expect(TokenType.RETURN)
        if self.peek().type in (TokenType.RBRACE, TokenType.SEMI, TokenType.EOF):
            if self.peek().type == TokenType.SEMI: self.advance()
            return ReturnStmt(None)
        expr = self.parse_expr()
        if self.peek().type == TokenType.SEMI: self.advance()
        return ReturnStmt(expr)

    def parse_expr(self): return self.parse_or()
    def parse_or(self):
        left = self.parse_and()
        while self.peek().type == TokenType.OR: self.advance(); right = self.parse_and(); left = BinOp(left, '||', right)
        return left
    def parse_and(self):
        left = self.parse_cmp()
        while self.peek().type == TokenType.AND: self.advance(); right = self.parse_cmp(); left = BinOp(left, '&&', right)
        return left
    def parse_cmp(self):
        left = self.parse_add()
        while self.peek().type in (TokenType.EQ, TokenType.NEQ, TokenType.LT, TokenType.GT, TokenType.LTE, TokenType.GTE):
            op = self.advance().value; right = self.parse_add(); left = BinOp(left, op, right)
        return left
    def parse_add(self):
        left = self.parse_mul()
        while self.peek().type in (TokenType.PLUS, TokenType.MINUS):
            op = self.advance().value; right = self.parse_mul(); left = BinOp(left, op, right)
        return left
    def parse_mul(self):
        left = self.parse_unary()
        while self.peek().type in (TokenType.MULT, TokenType.DIV, TokenType.MOD):
            op = self.advance().value; right = self.parse_unary(); left = BinOp(left, op, right)
        return left
    def parse_unary(self):
        if self.peek().type == TokenType.NOT: self.advance(); return UnOp(self.parse_unary(), '!')
        if self.peek().type in (TokenType.PLUS, TokenType.MINUS): op = self.advance().value; return UnOp(self.parse_unary(), op)
        return self.parse_primary()
    def parse_primary(self):
        t = self.peek()
        if t.type == TokenType.LPAREN: self.advance(); e = self.parse_expr(); self.expect(TokenType.RPAREN); return e
        if t.type == TokenType.BOOL: self.advance(); return Literal(True if t.value == 'TRUE' else False)
        if t.type == TokenType.NUMBER: self.advance(); val = t.value; return Literal(float(val) if '.' in val else int(val))
        if t.type == TokenType.STRING: self.advance(); return Literal(t.value.strip('"'))
        if t.type == TokenType.IDENTIFIER:
            ident = self.advance().value
            if self.peek().type == TokenType.LPAREN:
                self.expect(TokenType.LPAREN); args, kwargs = [], {}
                while self.peek().type != TokenType.RPAREN:
                    if self.peek(1).type == TokenType.ASSIGN: 
                        kw = self.advance().value; self.expect(TokenType.ASSIGN); kwargs[kw] = self.parse_expr()
                    else: args.append(self.parse_expr())
                    if self.peek().type == TokenType.COMMA: self.advance()
                self.expect(TokenType.RPAREN); return CallExpr(ident, args, kwargs)
            if self.peek().type == TokenType.LBRACK:
                self.expect(TokenType.LBRACK); idx = self.parse_expr(); self.expect(TokenType.RBRACK); return IndexExpr(Var(ident), idx)
            return Var(ident)
        raise ParseError(f"Unexpected {t}")

# ---- Interpreter ----
class Interpreter:
    def __init__(self, task_name, params, workspace, output, stdout="", stderr="", results=None):
        self.task_name = task_name; self.params = params
        self.workspace = workspace; self.output = output
        self.stdout = stdout; self.stderr = stderr
        self.vars: Dict[str, Any] = {}; self.results = results or {}

    def evaluate(self, expr):
        if isinstance(expr, Literal): return expr.value
        if isinstance(expr, Var): 
            if expr.name in self.vars: return self.vars[expr.name]
            if expr.name in self.params: return self.params[expr.name]
            return False
        if isinstance(expr, BinOp):
            l = self.evaluate(expr.left); r = self.evaluate(expr.right)
            if expr.op == '+': return l + r
            if expr.op == '-': return l - r
            if expr.op == '*': return l * r
            if expr.op == '/': return l / r
            if expr.op == '%': return l % r
            if expr.op == '==': return l == r
            if expr.op != '=': return l != r
            if expr.op == '<': return l < r
            if expr.op == '>': return l > r
            if expr.op == '<=': return l <= r
            if expr.op == '>=': return l >= r
            if expr.op == '&&': return l and r
            if expr.op == '||': return l or r
            raise ValueError(expr.op)
        if isinstance(expr, UnOp):
            v = self.evaluate(expr.operand)
            if expr.op == '!': return not v
            if expr.op == '+': return +v
            if expr.op == '-': return -v
            raise ValueError(expr.op)
        if isinstance(expr, CallExpr): return self.call_func(expr)
        if isinstance(expr, IndexExpr): return self.evaluate(expr.target)[self.evaluate(expr.idx)]
        raise ValueError(str(type(expr)))

    def call_func(self, c):
        n = c.name
        if n == 'len': return len(self.evaluate(c.args[0]))
        if n == 'contains':
            src = self.evaluate(c.args[0]); pat = self.evaluate(c.args[1])
            txt = (self.stdout if src == 'stdout' else self.stderr if src == 'stderr' else self._read_file(str(src)))
            return pat in txt
        if n == 'equals':
            src = self.evaluate(c.args[0]); exp = str(self.evaluate(c.args[1]))
            txt = (self.stdout.strip() if src == 'stdout' else self.stderr.strip() if src == 'stderr' 
                   else self._read_file(str(src)).strip())
            return txt == exp
        if n == 'exists': return os.path.exists(os.path.join(self.workspace, str(self.evaluate(c.args[0]))))
        if n == 'fail': return not self.results.get(str(c.args[0].name), True)
        return False

    def _read_file(self, src):
        try: return open(os.path.join(self.workspace, src)).read()
        except: return ""

    def eval_stmt(self, stmt):
        if isinstance(stmt, AssignStmt):
            self.vars[stmt.name] = self.evaluate(stmt.value)
            return self.vars[stmt.name]
        if isinstance(stmt, ForStmt):
            result = None; self.eval_stmt(stmt.init) if stmt.init else None
            while self.evaluate(stmt.cond):
                try:
                    for s in stmt.body.stmts: result = self.eval_stmt(s)
                    if stmt.update: self.eval_stmt(stmt.update)
                except BreakException: break
                except ContinueException: pass
            return result
        if isinstance(stmt, WhileStmt):
            result = None
            while self.evaluate(stmt.cond):
                try:
                    for s in stmt.body.stmts: result = self.eval_stmt(s)
                except BreakException: break
                except ContinueException: pass
            return result
        if isinstance(stmt, IfStmt):
            for c in stmt.clauses:
                cond_true = (c.cond is None) or self.evaluate(c.cond)
                if cond_true:
                    result = None
                    for s in c.body.stmts: result = self.eval_stmt(s)
                    return result
            return None
        if isinstance(stmt, Block):
            result = None
            for s in stmt.stmts: result = self.eval_stmt(s)
            return result
        if isinstance(stmt, ReturnStmt):
            return BreakException() if stmt.expr is None else self.evaluate(stmt.expr)
        if isinstance(stmt, BreakStmt): raise BreakException()
        if isinstance(stmt, ContinueStmt): raise ContinueException()
        if isinstance(stmt, ExprStmt): return self.evaluate(stmt.expr)
        raise ValueError(str(type(stmt)))

class BreakException(Exception): pass
class ContinueException(Exception): pass

# ---- Executor ----
@dataclass
class Job:
    job_id: int; task: str; params: Dict[str, Any]; parent: Optional[int] = None
    stdout: str = ""; stderr: str = ""; timed_out: bool = False
    success: Dict[str, bool] = field(default_factory=dict)
    output: Optional[str] = None; exit_code: int = 0; duration: float = 0.0

class Executor:
    def __init__(self, prog, ws, out, clean_cwd=False):
        self.prog = prog; self.ws = ws; self.out = out; self.clean_cwd = clean_cwd
        self.jobs: List[Job] = []; self.jc = 0; self.results: Dict[str, bool] = {}
        self.jsonl_path = os.path.join(out, "jobs.jsonl")

    def run(self, entry, params):
        jid = self._new_job(entry, params, None)
        try:
            self._exec(jid)
            return 1 if self.jobs[jid].exit_code != 0 else 0
        except ValidationError as e:
            print(f"INVALID_PIPE:{e.msg}", file=sys.stderr); sys.exit(3)
        except Exception as e:
            print(f"INVALID_PIPE:{e}", file=sys.stderr); sys.exit(3)

    def _new_job(self, task, params, parent):
        self.jc += 1
        self.jobs.append(Job(self.jc, task, params, parent)); return self.jc

    def _exec(self, jid):
        job = self.jobs[jid]; task = self.prog.tasks[job.task]
        self._emit("TASK_STARTED", job.job_id, job.task, job.params, job.parent)
        s = time.time()

        if task.requires:
            interp = self._make_interp(job)
            try: interp.eval_stmt(task.requires)
            except BreakException: pass

        if task.run:
            wd = self.ws
            if self.clean_cwd and os.path.exists(wd):
                import shutil
                for item in os.listdir(wd):
                    p = os.path.join(wd, item)
                    if os.path.isfile(p): os.remove(p)
                    else: shutil.rmtree(p)
            cmds = [self._resolve(c, job.params) for c in task.run.cmds]
            cmd = "\n".join(cmds)
            try:
                r = subprocess.run(cmd, shell=True, cwd=wd, capture_output=True, text=True, timeout=task.timeout)
                job.stdout = self._clean(r.stdout); job.stderr = self._clean(r.stderr); job.exit_code = r.returncode
            except subprocess.TimeoutExpired:
                job.stdout = ""; job.stderr = f"Timeout after {task.timeout}s\n"; job.exit_code = 124; job.timed_out = True

        if task.success:
            interp = self._make_interp(job)
            for name, expr in task.success.items():
                try: job.success[name] = interp.evaluate(expr)
                except: job.success[name] = False

        if task.success and job.success and not all(job.success.values()): job.exit_code = 1
        job.duration = time.time() - s
        self.results[job.task] = (job.exit_code == 0)
        self._write_jsonl(job)
        self._emit("TASK_COMPLETED" if job.exit_code == 0 else "TASK_FAILED",
                   job.job_id, job.task, job.params, job.parent, job.success)

    def _make_interp(self, job):
        out = job.output or self.out
        return Interpreter(job.task, job.params, self.ws, out, job.stdout, job.stderr, self.results)

    def _resolve(self, cmd, params):
        for k, v in params.items(): cmd = cmd.replace(f"${{params.{k}}}", str(v))
        cmd = cmd.replace("${workspace}", self.ws)
        return cmd.replace("${output}", self.out or "")

    def _clean(self, t):
        return t.replace(chr(8216), "'").replace(chr(8217), "'").replace(chr(8220), '"').replace(chr(8221), '"')

    def _emit(self, evt, jid, task, params, parent, success=None):
        msg = {"event": evt, "job_id": jid, "task": task}
        if parent is not None: msg["parent"] = parent
        print(json.dumps(msg))

    def _write_jsonl(self, job):
        rec = {
            "job_id": job.job_id, "task": job.task, "params": job.params,
            "stdout": job.stdout, "stderr": job.stderr, "timed_out": job.timed_out,
            "success": job.success, "output": job.output, "exit_code": job.exit_code,
            "parent": job.parent, "duration": job.duration
        }
        mode = "a" if os.path.exists(self.jsonl_path) else "w"
        with open(self.jsonl_path, mode) as f:
            if mode == "a": f.write("\n")
            json.dump(rec, f)

# ---- Config ----
def load_config(path):
    if toml is None: raise ImportError("toml needed for config")
    data = toml.load(path)
    entry = data.get("entry", "main")
    entry_name = entry if isinstance(entry, str) else str(entry)
    entry_params = {}
    if isinstance(entry, str) and "(" in entry and ")" in entry:
        m = re.match(r"(\w+)\((.+)\)", entry)
        if m:
            entry_name = m.group(1)
            for part in [p.strip() for p in m.group(2).split(",") if p.strip()]:
                if "=" in part:
                    k, v = part.split("=", 1)
                    k = k.strip(); v = v.strip().strip('"').strip("'")
                    if v.upper() == "TRUE": v = True
                    elif v.upper() == "FALSE": v = False
                    elif v.isdigit(): v = int(v)
                    elif all(c.isdigit() or c == '.' for c in v): v = float(v)
                    entry_params[k] = v
    clean_cwd = data.get("clean_cwd", False)
    if "env" in data:
        for k, v in data["env"].items(): os.environ[k] = str(v)
    return entry_name, entry_params, clean_cwd

# ---- CLI ----
